// ══════════════════════════════════════════════════════════════════════════════
// AUTH — ONBOARDING & LOGIN
// ══════════════════════════════════════════════════════════════════════════════
function AuthScreen({onAuthed}) {
  const [mode,setMode]       = useState("welcome") // welcome | login | signup | setup
  const [step,setStep]       = useState(1) // setup steps 1-4
  const [email,setEmail]     = useState("")
  const [password,setPassword] = useState("")
  const [businessName,setBusinessName] = useState("")
  const [businessType,setBusinessType] = useState("independent") // independent | franchise
  const [franchiseCode,setFranchiseCode] = useState("")
  const [error,setError]     = useState("")
  const [working,setWorking] = useState(false)

  const handleLogin = async () => {
    setError(""); setWorking(true)
    const {data,error:err} = await supabase.auth.signInWithPassword({email,password})
    if(err){ setError(err.message); setWorking(false); return }
    // Check if business exists
    const {data:biz} = await supabase.from("bb_businesses").select("id").eq("owner_id",data.user.id).single()
    if(!biz){ setMode("setup"); setStep(1) }
    else { onAuthed() }
    setWorking(false)
  }

  const [authUserId, setAuthUserId] = useState(null)

  const handleSignup = async () => {
    setError(""); setWorking(true)
    if(password.length<6){ setError("Password must be at least 6 characters"); setWorking(false); return }
    const {data,error:err} = await supabase.auth.signUp({email,password})
    if(err){ setError(err.message); setWorking(false); return }
    // Store the user id — works whether email confirmation is on or off
    const userId = data?.user?.id || data?.session?.user?.id
    if(!userId){ setError("Signup failed — please try again"); setWorking(false); return }
    setAuthUserId(userId)
    setMode("setup"); setStep(1); setWorking(false)
  }

  const handleCreateBusiness = async () => {
    setError(""); setWorking(true)
    // Try to get user from session first, fall back to stored id from signup
    const {data:userData} = await supabase.auth.getUser()
    const userId = userData?.user?.id || authUserId
    if(!userId){ setError("Session expired — please sign up again"); setWorking(false); return }
    const slug = businessName.toLowerCase().replace(/[^a-z0-9]/g,"-")
    const {error:err} = await supabase.from("bb_businesses").insert({
      name: businessName.trim(),
      slug: `${slug}-${Math.random().toString(36).slice(2,6)}`,
      owner_id: userId,
      plan_id: "free",
      trial_ends_at: new Date(Date.now()+14*24*60*60*1000).toISOString(),
      is_franchise_hq: businessType==="franchise",
    })
    if(err){ setError(err.message); setWorking(false); return }
    const {data:biz} = await supabase.from("bb_businesses").select("id").eq("owner_id",userId).single()
    if(!biz){ setError("Business not found after creation"); setWorking(false); return }
    await supabase.from("bb_staff").insert({
      business_id: biz.id,
      auth_user_id: userId,
      name: email.split("@")[0],
      role: "owner",
      initials: email.slice(0,2).toUpperCase(),
      active: true,
      pin: "0000",
    })
    setWorking(false)
    onAuthed()
  }

  // Welcome screen
  if(mode==="welcome") return (
    <div style={{minHeight:"100vh",background:C.bg,display:"flex"}}>
      {/* Left panel - branding */}
      <div style={{width:"45%",background:C.sidebar,display:"flex",flexDirection:"column",justifyContent:"center",padding:"48px 56px"}}>
        <div style={{marginBottom:32}}>
          <img src={LOGO_LG} alt="BrewBase" style={{width:180,height:180,objectFit:"contain"}}/>
        </div>
        <div style={{marginTop:48}}>
          <h1 style={{fontSize:38,fontWeight:800,color:"#fff",margin:"0 0 16px",fontFamily:"Playfair Display,serif",lineHeight:1.2}}>
            Smart POS.<br/>Stronger Cafés.
          </h1>
          <p style={{fontSize:15,color:"rgba(255,255,255,.55)",lineHeight:1.7,marginBottom:40}}>
            The all-in-one management platform built specifically for coffee shops. Run your POS, track inventory, manage staff, and grow customer loyalty — all in one place.
          </p>
          <div style={{display:"flex",flexDirection:"column",gap:12}}>
            {["☕ Full POS with modifier support","📊 Real-time sales dashboard","👥 Staff & shift management","📦 Inventory & supplier tracking","🎯 Built-in loyalty programme","🖨 Bluetooth receipt printing"].map(f=>(
              <div key={f} style={{fontSize:14,color:"rgba(255,255,255,.6)",display:"flex",alignItems:"center",gap:10}}>
                <div style={{width:20,height:20,borderRadius:"50%",background:C.primaryPale,border:`1px solid ${C.primary}`,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>
                  <div style={{width:6,height:6,borderRadius:"50%",background:C.primary}}/>
                </div>
                {f}
              </div>
            ))}
          </div>
        </div>
        <div style={{marginTop:"auto",paddingTop:40}}>
          <div style={{fontSize:12,color:"rgba(255,255,255,.3)",letterSpacing:1}}>BUILT FOR CAFÉS. DESIGNED FOR GROWTH.</div>
        </div>
      </div>
      {/* Right panel - actions */}
      <div style={{flex:1,display:"flex",alignItems:"center",justifyContent:"center",padding:48}}>
        <div style={{maxWidth:380,width:"100%"}}>
          <h2 style={{fontSize:28,fontWeight:800,color:C.black,margin:"0 0 8px",fontFamily:"Playfair Display,serif"}}>Get started today</h2>
          <p style={{color:C.muted,marginBottom:36,fontSize:14}}>14-day free trial. No credit card required.</p>
          <div style={{display:"flex",flexDirection:"column",gap:12}}>
            <Btn size="lg" onClick={()=>setMode("signup")} style={{width:"100%",background:C.primary,fontSize:16,padding:"16px 24px"}}>
              Create free account →
            </Btn>
            <Btn size="lg" variant="secondary" onClick={()=>setMode("login")} style={{width:"100%",fontSize:16,padding:"16px 24px"}}>
              Sign in
            </Btn>
          </div>
          <div style={{marginTop:32,padding:"20px",background:C.faint,borderRadius:12,border:`1px solid ${C.border}`}}>
            <div style={{fontSize:13,fontWeight:600,color:C.black,marginBottom:8}}>Subscription Plans</div>
            <div style={{display:"flex",flexDirection:"column",gap:6}}>
              {[{name:"Free",price:"R0/month",desc:"Basic POS, 1 staff, 50 products"},
                {name:"Pro",price:"R499/month",desc:"Unlimited everything + accounting"},
                {name:"Enterprise",price:"Custom",desc:"Franchise & multi-store"}].map(p=>(
                <div key={p.name} style={{display:"flex",justifyContent:"space-between",alignItems:"center",fontSize:13}}>
                  <div>
                    <span style={{fontWeight:600,color:C.black}}>{p.name}</span>
                    <span style={{color:C.muted,marginLeft:6}}>{p.desc}</span>
                  </div>
                  <span style={{color:C.primary,fontWeight:700,flexShrink:0,marginLeft:8}}>{p.price}</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  )

  // Login screen
  if(mode==="login") return (
    <div style={{minHeight:"100vh",background:C.bg,display:"flex",alignItems:"center",justifyContent:"center",padding:24}}>
      <div style={{maxWidth:400,width:"100%"}}>
        <div style={{marginBottom:32}}><BrewBaseLogo size={40}/></div>
        <h2 style={{fontSize:28,fontWeight:800,color:C.white,margin:"0 0 8px",fontFamily:"Playfair Display,serif"}}>Welcome back</h2>
        <p style={{color:C.muted,marginBottom:32,fontSize:14}}>Sign in to your BrewBase account</p>
        <div style={{display:"flex",flexDirection:"column",gap:16}}>
          <Input label="Email address" type="email" value={email} onChange={e=>setEmail(e.target.value)} placeholder="you@yourcafe.co.za"/>
          <Input label="Password" type="password" value={password} onChange={e=>setPassword(e.target.value)} placeholder="••••••••"/>
          {error&&<div style={{background:"#fff0f0",border:`1px solid ${C.red}44`,borderRadius:8,padding:"10px 14px",fontSize:13,color:C.red}}>{error}</div>}
          <Btn size="lg" onClick={handleLogin} disabled={working} style={{width:"100%",background:`linear-gradient(135deg,${C.primary},${C.blue})`}}>
            {working?"Signing in…":"Sign In"}
          </Btn>
          <div style={{textAlign:"center",fontSize:14,color:C.muted}}>
            Don't have an account?{" "}
            <button onClick={()=>setMode("signup")} style={{background:"none",border:"none",color:C.primary,cursor:"pointer",fontWeight:600,fontSize:14}}>Create one free</button>
          </div>
        </div>
      </div>
    </div>
  )

  // Signup screen
  if(mode==="signup") return (
    <div style={{minHeight:"100vh",background:C.bg,display:"flex",alignItems:"center",justifyContent:"center",padding:24}}>
      <div style={{maxWidth:400,width:"100%"}}>
        <div style={{marginBottom:32}}><BrewBaseLogo size={40}/></div>
        <h2 style={{fontSize:28,fontWeight:800,color:C.white,margin:"0 0 8px",fontFamily:"Playfair Display,serif"}}>Create your account</h2>
        <p style={{color:C.muted,marginBottom:32,fontSize:14}}>14-day free trial · No credit card required</p>
        <div style={{display:"flex",flexDirection:"column",gap:16}}>
          <Input label="Email address" type="email" value={email} onChange={e=>setEmail(e.target.value)} placeholder="you@yourcafe.co.za" required/>
          <Input label="Password" type="password" value={password} onChange={e=>setPassword(e.target.value)} placeholder="At least 6 characters" required/>
          {error&&<div style={{background:"#fff0f0",border:`1px solid ${C.red}44`,borderRadius:8,padding:"10px 14px",fontSize:13,color:C.red}}>{error}</div>}
          <Btn size="lg" onClick={handleSignup} disabled={working||!email||!password} style={{width:"100%",background:`linear-gradient(135deg,${C.primary},${C.blue})`}}>
            {working?"Creating account…":"Create Account"}
          </Btn>
          <div style={{textAlign:"center",fontSize:14,color:C.muted}}>
            Already have an account?{" "}
            <button onClick={()=>setMode("login")} style={{background:"none",border:"none",color:C.primary,cursor:"pointer",fontWeight:600,fontSize:14}}>Sign in</button>
          </div>
        </div>
      </div>
    </div>
  )

  // Setup flow
  if(mode==="setup") return (
    <div style={{minHeight:"100vh",background:C.bg,display:"flex",alignItems:"center",justifyContent:"center",padding:24}}>
      <div style={{maxWidth:540,width:"100%"}}>
        <div style={{marginBottom:32,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
          <BrewBaseLogo size={36}/>
          <div style={{display:"flex",gap:8}}>
            {[1,2].map(s=>(
              <div key={s} style={{width:32,height:4,borderRadius:2,background:step>=s?C.primary:C.faint}}/>
            ))}
          </div>
        </div>
        {step===1&&(
          <>
            <h2 style={{fontSize:28,fontWeight:800,color:C.white,margin:"0 0 8px",fontFamily:"Playfair Display,serif"}}>Tell us about your business</h2>
            <p style={{color:C.muted,marginBottom:32,fontSize:14}}>We'll set everything up for you</p>
            <div style={{display:"flex",flexDirection:"column",gap:20}}>
              <Input label="Business name" value={businessName} onChange={e=>setBusinessName(e.target.value)} placeholder="e.g. Ruah Brew, Bean Scene" required/>
              <div>
                <label style={{fontSize:13,color:C.muted,fontWeight:500,marginBottom:10,display:"block"}}>Business type</label>
                <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
                  {[
                    {id:"independent",icon:"🏠",title:"Independent",desc:"My own café"},
                    {id:"franchise",icon:"🏢",title:"Franchise",desc:"Part of a franchise group"},
                  ].map(opt=>(
                    <div key={opt.id} onClick={()=>setBusinessType(opt.id)} style={{
                      background:businessType===opt.id?C.primaryPale:C.elevated,
                      border:`2px solid ${businessType===opt.id?C.primary:C.border}`,
                      borderRadius:12,padding:16,cursor:"pointer",textAlign:"center",transition:"all 0.15s"
                    }}>
                      <div style={{fontSize:28,marginBottom:6}}>{opt.icon}</div>
                      <div style={{fontSize:15,fontWeight:700,color:C.white,marginBottom:2}}>{opt.title}</div>
                      <div style={{fontSize:12,color:C.muted}}>{opt.desc}</div>
                    </div>
                  ))}
                </div>
              </div>
              {businessType==="franchise"&&(
                <Input label="Franchise code" value={franchiseCode} onChange={e=>setFranchiseCode(e.target.value)} placeholder="Enter the code from your franchise"/>
              )}
              {error&&<div style={{background:"#fff0f0",border:`1px solid ${C.red}44`,borderRadius:8,padding:"10px 14px",fontSize:13,color:C.red}}>{error}</div>}
              <Btn size="lg" onClick={()=>setStep(2)} disabled={!businessName.trim()} style={{width:"100%",background:`linear-gradient(135deg,${C.primary},${C.blue})`}}>
                Continue →
              </Btn>
            </div>
          </>
        )}
        {step===2&&(
          <>
            <h2 style={{fontSize:28,fontWeight:800,color:C.white,margin:"0 0 8px",fontFamily:"Playfair Display,serif"}}>You're all set!</h2>
            <p style={{color:C.muted,marginBottom:32,fontSize:14}}>Here's what's included in your free 14-day trial</p>
            <div style={{display:"flex",flexDirection:"column",gap:10,marginBottom:32}}>
              {[
                {icon:"☕",t:"Full POS system",d:"Take orders, manage payment, print receipts"},
                {icon:"📊",t:"Live dashboard",d:"See your sales, tips and top items in real time"},
                {icon:"📦",t:"Inventory tracking",d:"Monitor stock levels and get reorder alerts"},
                {icon:"👥",t:"Staff management",d:"Add staff, set PINs, track shifts and hours"},
                {icon:"💰",t:"Basic accounting",d:"Track expenses, view P&L"},
                {icon:"🎯",t:"Loyalty programme",d:"Reward your regulars with points"},
              ].map(f=>(
                <div key={f.t} style={{display:"flex",alignItems:"flex-start",gap:14,padding:"12px 16px",background:C.elevated,borderRadius:10}}>
                  <span style={{fontSize:22,flexShrink:0}}>{f.icon}</span>
                  <div>
                    <div style={{fontSize:14,fontWeight:600,color:C.white}}>{f.t}</div>
                    <div style={{fontSize:12,color:C.muted}}>{f.d}</div>
                  </div>
                  <span style={{color:C.green,fontSize:16,marginLeft:"auto",flexShrink:0}}>✓</span>
                </div>
              ))}
            </div>
            {error&&<div style={{background:C.redPale,border:`1px solid ${C.red}`,borderRadius:8,padding:"10px 14px",fontSize:13,color:C.red,marginBottom:16}}>{error}</div>}
            <Btn size="lg" onClick={handleCreateBusiness} disabled={working} style={{width:"100%",background:`linear-gradient(135deg,${C.primary},${C.blue})`}}>
              {working?"Setting up your account…":"Launch BrewBase →"}
            </Btn>
          </>
        )}
      </div>
    </div>
  )

  return null
}

