// APP SHELL
// ══════════════════════════════════════════════════════════════════════════════
const NAV_ITEMS = [
  {id:"dashboard", icon:"📊", label:"Dashboard",    roles:["owner","manager","barista","cashier"]},
  {id:"pos",       icon:"🛒", label:"Point of Sale", roles:["owner","manager","barista","cashier"]},
  {id:"orders",    icon:"📋", label:"Orders",        roles:["owner","manager"]},
  {id:"shifts",    icon:"🕐", label:"Shifts",        roles:["owner","manager","barista","cashier"]},
  {id:"menu",      icon:"☕", label:"Menu",          roles:["owner","manager"]},
  {id:"inventory", icon:"📦", label:"Inventory",     roles:["owner","manager"]},
  {id:"staff",     icon:"👥", label:"Staff",         roles:["owner","manager"]},
  {id:"accounting",icon:"💰", label:"Accounting",    roles:["owner","manager"]},
  {id:"reports",   icon:"📈", label:"Reports",       roles:["owner","manager"]},
  {id:"customers", icon:"🎯", label:"Customers",     roles:["owner","manager"]},
  {id:"printer",       icon:"🖨️", label:"Printer",       roles:["owner","manager"]},
  {id:"franchise",     icon:"🏢", label:"Franchise",     roles:["owner"]},
  {id:"owner",         icon:"📱", label:"Owner View",    roles:["owner"]},
  {id:"waste",         icon:"🗑️", label:"Waste Log",     roles:["owner","manager"]},
  {id:"purchase_orders",icon:"📬",label:"Purchase Orders",roles:["owner","manager"]},
  {id:"invoices",      icon:"🧾", label:"Invoices",      roles:["owner","manager"]},
  {id:"bank_recon",    icon:"🏦", label:"Bank Recon",    roles:["owner","manager"]},
  {id:"settings",      icon:"⚙️", label:"Settings",      roles:["owner","manager"]},
]

function AppShell({business, staff, onLogout}) {
  const [active,setActive]   = useState("pos")
  const [sidebarOpen,setSidebarOpen] = useState(false)
  const pinTimeoutRef = useRef(null)

  const allowedNav = NAV_ITEMS.filter(n=>n.roles.includes(staff?.role||"barista"))

  // Auto-logout after 10 minutes inactivity
  const resetTimer = useCallback(()=>{
    if(pinTimeoutRef.current) clearTimeout(pinTimeoutRef.current)
    pinTimeoutRef.current = setTimeout(onLogout, 10*60*1000)
  },[onLogout])

  useEffect(()=>{
    const events = ["mousedown","touchstart","keydown"]
    events.forEach(e=>window.addEventListener(e,resetTimer,{passive:true}))
    resetTimer()
    return ()=>{
      events.forEach(e=>window.removeEventListener(e,resetTimer))
      if(pinTimeoutRef.current) clearTimeout(pinTimeoutRef.current)
    }
  },[resetTimer])

  const MODULES = {
    dashboard: <DashboardModule/>,
    pos:       <POSModule/>,
    orders:    <OrdersModule/>,
    shifts:    <ShiftsModule/>,
    menu:      <MenuModule/>,
    inventory: <InventoryModule/>,
    staff:     <StaffModule/>,
    accounting:<AccountingModule/>,
    reports:   <ReportsModule/>,
    customers: <CustomersModule/>,
    printer:   <PrinterModule/>,
    franchise: <FranchiseModule/>,
    owner:         <OwnerDashboardModule/>,
    waste:         <WasteLogModule/>,
    purchase_orders:<PurchaseOrdersModule/>,
    invoices:      <InvoicesModule/>,
    bank_recon:    <BankReconciliationModule/>,
    settings:      <SettingsModule onLogout={onLogout}/>,
  }

  const currentMod = allowedNav.find(n=>n.id===active)||allowedNav[0]

  const [mobileNavOpen, setMobileNavOpen] = useState(false)
  const [pinPromptDone, setPinPromptDone] = useState(false)

  return (
    <div style={{display:"flex",height:"100vh",background:C.bg,overflow:"hidden",fontFamily:"Inter,sans-serif"}}>
      <OfflineBanner/>
      {!pinPromptDone&&<FirstLoginPinPrompt staff={staff} onDone={()=>setPinPromptDone(true)}/>}
      <style>{`
        @keyframes spin { to { transform:rotate(360deg) } }
        * { box-sizing:border-box; }
        ::-webkit-scrollbar { width:5px; height:5px; }
        ::-webkit-scrollbar-track { background:transparent; }
        ::-webkit-scrollbar-thumb { background:${C.border}; border-radius:4px; }
        input,select,textarea,button { font-family:Inter,sans-serif; }
      `}</style>

      {/* Mobile backdrop */}
      {mobileNavOpen&&(
        <div onClick={()=>setMobileNavOpen(false)}
          style={{position:"fixed",inset:0,background:"rgba(0,0,0,.5)",zIndex:200,display:"none"}}
          className="mobile-backdrop"/>
      )}

      {/* ── SIDEBAR (persistent on tablet, slide-out on phone) ── */}
      <div style={{
        width:220,flexShrink:0,background:C.sidebar,
        display:"flex",flexDirection:"column",overflow:"hidden",
        borderRight:`1px solid rgba(255,255,255,.06)`
      }}>
        {/* Logo */}
        <div style={{padding:"22px 18px 16px",borderBottom:"1px solid rgba(255,255,255,.08)"}}>
          <BrewBaseLogo size={32} light={true}/>
        </div>

        {/* Staff avatar */}
        <div style={{padding:"14px 16px",borderBottom:"1px solid rgba(255,255,255,.08)",display:"flex",alignItems:"center",gap:10}}>
          <div style={{width:34,height:34,borderRadius:"50%",background:C.primary,
            display:"flex",alignItems:"center",justifyContent:"center",fontSize:13,fontWeight:700,color:"#fff",flexShrink:0}}>
            {staff?.initials||staff?.name?.slice(0,2).toUpperCase()||"?"}
          </div>
          <div>
            <div style={{fontSize:13,fontWeight:600,color:"#fff",lineHeight:1}}>{staff?.name}</div>
            <div style={{fontSize:11,color:"rgba(255,255,255,.4)",textTransform:"capitalize",marginTop:2}}>{staff?.role}</div>
          </div>
        </div>

        {/* Nav items */}
        <nav style={{flex:1,padding:"10px 8px",overflowY:"auto",display:"flex",flexDirection:"column",gap:1}}>
          {allowedNav.map(item=>{
            const isA = active===item.id
            return (
              <button key={item.id} onClick={()=>{ setActive(item.id); setMobileNavOpen(false); }}
                style={{display:"flex",alignItems:"center",gap:10,padding:"11px 10px",borderRadius:8,
                  border:"none",cursor:"pointer",textAlign:"left",width:"100%",
                  background:isA?"rgba(74,124,89,.25)":"transparent",
                  color:isA?"#fff":"rgba(255,255,255,.45)",
                  transition:"all 0.15s"}}>
                <span style={{fontSize:17,opacity:isA?1:0.7,flexShrink:0}}>{item.icon}</span>
                <span style={{fontSize:13,fontWeight:isA?600:400}}>{item.label}</span>
                {isA&&<div style={{width:3,height:20,borderRadius:2,background:C.primary,marginLeft:"auto"}}/>}
              </button>
            )
          })}
        </nav>

        {/* Bottom: business info + logout */}
        <div style={{padding:"12px 8px",borderTop:"1px solid rgba(255,255,255,.08)",display:"flex",flexDirection:"column",gap:6}}>
          <div style={{padding:"8px 10px",borderRadius:8,background:"rgba(255,255,255,.05)"}}>
            <div style={{fontSize:12,fontWeight:600,color:"rgba(255,255,255,.7)",marginBottom:2,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{business?.name}</div>
            <span style={{fontSize:10,background:C.primary,color:"#fff",padding:"2px 7px",borderRadius:10,fontWeight:600,textTransform:"uppercase"}}>{business?.plan_id||"FREE"}</span>
          </div>
          <button onClick={onLogout} style={{display:"flex",alignItems:"center",gap:8,padding:"9px 10px",borderRadius:8,
            border:"none",cursor:"pointer",background:"rgba(214,69,69,.15)",color:"rgba(214,69,69,.8)",width:"100%",fontSize:13,fontWeight:500}}>
            <span>↪</span> Log Out
          </button>
        </div>
      </div>

      {/* ── MAIN CONTENT ── */}
      <div style={{flex:1,display:"flex",flexDirection:"column",overflow:"hidden"}}>
        {/* Top bar */}
        <div style={{padding:"0 24px",height:58,borderBottom:`1px solid ${C.border}`,background:C.surface,
          display:"flex",alignItems:"center",gap:16,flexShrink:0,boxShadow:"0 1px 3px rgba(0,0,0,.04)"}}>
          <div style={{flex:1}}>
            <div style={{fontSize:18,fontWeight:700,color:C.black,fontFamily:"Playfair Display,serif"}}>
              {currentMod?.label}
            </div>
          </div>
          <div style={{fontSize:13,color:C.muted}}>
            {new Date().toLocaleDateString("en-ZA",{weekday:"short",day:"numeric",month:"short"})}
          </div>
          <div style={{display:"flex",alignItems:"center",gap:6,padding:"5px 12px",borderRadius:20,background:C.greenPale,border:`1px solid ${C.primary}30`}}>
            <div style={{width:7,height:7,borderRadius:"50%",background:C.primary}}/>
            <span style={{fontSize:12,color:C.primary,fontWeight:600}}>Synced</span>
          </div>
        </div>

        {/* Module */}
        <div style={{flex:1,overflowY:"auto",background:C.bg}}>
          <StaffCtx.Provider value={staff}>
            {MODULES[active||"pos"]}
          </StaffCtx.Provider>
        </div>
      </div>
    </div>
  )
}

