// PLACEHOLDER MODULES (will be replaced one by one)
// ══════════════════════════════════════════════════════════════════════════════
// ══════════════════════════════════════════════════════════════════════════════
// DASHBOARD
// ══════════════════════════════════════════════════════════════════════════════
function DashboardModule() {
  const business = useBusiness()
  const {data:orders}    = useData("bb_orders")
  const {data:expenses}  = useData("bb_expenses")
  const {data:inventory} = useData("bb_inventory")
  const [topRange,setTopRange] = useState("today")

  const today     = new Date().toISOString().slice(0,10)
  const yesterday = new Date(Date.now()-86400000).toISOString().slice(0,10)
  const weekStart = new Date(Date.now()-6*86400000).toISOString().slice(0,10)
  const monthPfx  = today.slice(0,7)

  const todayO  = orders.filter(o=>o.date===today&&o.status!=="refunded")
  const yestO   = orders.filter(o=>o.date===yesterday&&o.status!=="refunded")
  const monthO  = orders.filter(o=>String(o.date||"").startsWith(monthPfx)&&o.status!=="refunded")
  const monthExp= expenses.filter(e=>String(e.date||"").startsWith(monthPfx))

  const sum = (arr,f) => arr.reduce((s,o)=>s+parseFloat(o[f]||0),0)
  const todayRev  = sum(todayO,"total")
  const yestRev   = sum(yestO,"total")
  const monthRev  = sum(monthO,"total")
  const monthExpT = sum(monthExp,"amount")
  const profit    = monthRev - monthExpT
  const tipsToday = sum(todayO,"tip")
  const cardToday = todayO.filter(o=>o.method==="card").reduce((s,o)=>s+parseFloat(o.total||0),0)
  const cashToday = todayO.filter(o=>o.method==="cash").reduce((s,o)=>s+parseFloat(o.total||0),0)
  const eftToday  = todayO.filter(o=>o.method==="eft").reduce((s,o)=>s+parseFloat(o.total||0),0)
  const lowStock  = inventory.filter(i=>parseFloat(i.stock||0)<=parseFloat(i.reorder_level||0))
  const revTrend  = yestRev>0?Math.round(((todayRev-yestRev)/yestRev)*100):null
  const ordTrend  = yestO.length>0?todayO.length-yestO.length:null

  const calcTop = (list) => {
    const freq={}
    list.forEach(o=>{
      const items=typeof o.items==="string"?JSON.parse(o.items||"[]"):o.items||[]
      items.forEach(i=>{freq[i.name]=(freq[i.name]||0)+(i.qty||1)})
    })
    return Object.entries(freq).sort((a,b)=>b[1]-a[1]).slice(0,6)
  }
  const topItems = calcTop(topRange==="today"?todayO:orders.filter(o=>o.date>=weekStart&&o.status!=="refunded"))

  const hours=[]
  for(let h=6;h<=22;h++){
    const hStr=String(h).padStart(2,"0")
    const rev=todayO.filter(o=>String(o.time||"").startsWith(hStr)).reduce((s,o)=>s+parseFloat(o.total||0),0)
    hours.push({h,label:`${h>12?h-12:h===0?12:h}${h>=12?"pm":"am"}`,rev})
  }
  const maxRev=Math.max(...hours.map(h=>h.rev),1)

  return (
    <div style={{padding:24,display:"flex",flexDirection:"column",gap:20}}>
      <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(180px,1fr))",gap:14}}>
        <KPI label="Revenue Today" value={fmt(todayRev)} color={C.primary} trend={revTrend} icon="💰"/>
        <KPI label="Orders Today" value={todayO.length} color={C.blue} trend={ordTrend} trendLabel="vs yesterday" icon="🧾"/>
        <KPI label="Tips Today" value={fmt(tipsToday)} color={C.amber} sub="all staff" icon="🙏"/>
        <KPI label="Month Profit" value={fmt(profit)} color={profit>=0?C.primary:C.red} sub="revenue − expenses" icon="📈"/>
      </div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(140px,1fr))",gap:14}}>
        <KPI label="Card Today" value={fmt(cardToday)} icon="💳"/>
        <KPI label="Cash Today" value={fmt(cashToday)} icon="💵"/>
        <KPI label="EFT Today" value={fmt(eftToday)} icon="🏦"/>
        <KPI label="Low Stock Items" value={lowStock.length} color={lowStock.length>0?C.red:C.primary} sub={lowStock.length>0?lowStock.slice(0,2).map(i=>i.name).join(", "):"All good"} icon="📦"/>
      </div>
      <div style={{background:C.surface,borderRadius:14,padding:20,border:`1px solid ${C.border}`}}>
        <SHead>Sales by Hour — Today</SHead>
        <div style={{display:"flex",alignItems:"flex-end",gap:4,height:100}}>
          {hours.map(h=>(
            <div key={h.h} style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",gap:2}}>
              <div style={{width:"100%",background:h.rev>0?C.primary:C.faint,borderRadius:"3px 3px 0 0",height:`${Math.max(3,Math.round((h.rev/maxRev)*90))}px`,transition:"height 0.4s"}}/>
              <span style={{fontSize:9,color:C.light,whiteSpace:"nowrap",marginTop:4}}>{h.label}</span>
            </div>
          ))}
        </div>
        {todayO.length===0&&<div style={{textAlign:"center",color:C.muted,fontSize:13,marginTop:8}}>No sales recorded yet today</div>}
      </div>
      <div style={{display:"grid",gridTemplateColumns:"2fr 1fr",gap:16}}>
        <div style={{background:C.surface,borderRadius:14,padding:20,border:`1px solid ${C.border}`}}>
          <SHead>Today's Transactions</SHead>
          {todayO.length===0
            ? <Empty icon="☕" title="No sales yet today" message="Completed orders will appear here"/>
            : <div style={{overflowX:"auto"}}>
                <table style={{width:"100%",borderCollapse:"collapse"}}>
                  <thead><tr style={{borderBottom:`2px solid ${C.border}`}}>
                    {["Time","Items","Staff","Method","Table","Total"].map(h=>(
                      <th key={h} style={{padding:"8px 12px",textAlign:"left",fontSize:11,color:C.muted,fontWeight:700,textTransform:"uppercase",whiteSpace:"nowrap"}}>{h}</th>
                    ))}
                  </tr></thead>
                  <tbody>
                    {[...todayO].reverse().slice(0,12).map(o=>{
                      const items=typeof o.items==="string"?JSON.parse(o.items||"[]"):o.items||[]
                      return(
                        <tr key={o.id} style={{borderBottom:`1px solid ${C.border}`}}>
                          <td style={{padding:"10px 12px",fontSize:13,color:C.muted,whiteSpace:"nowrap"}}>{String(o.time||"").slice(0,5)}</td>
                          <td style={{padding:"10px 12px",fontSize:13,color:C.black,maxWidth:180,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{items.map(i=>i.name).join(", ")}</td>
                          <td style={{padding:"10px 12px",fontSize:13,color:C.muted,whiteSpace:"nowrap"}}>{o.staff_name||"—"}</td>
                          <td style={{padding:"10px 12px"}}><Chip color={o.method==="card"?"blue":o.method==="eft"?"primary":"amber"} size="sm">{o.method||"—"}</Chip></td>
                          <td style={{padding:"10px 12px",fontSize:13,color:C.muted}}>{o.table_num||"—"}</td>
                          <td style={{padding:"10px 12px",fontSize:15,fontWeight:800,color:C.primary,whiteSpace:"nowrap"}}>{fmt(o.total)}</td>
                        </tr>
                      )
                    })}
                  </tbody>
                </table>
              </div>
          }
        </div>
        <div style={{display:"flex",flexDirection:"column",gap:14}}>
          <div style={{background:C.surface,borderRadius:14,padding:20,border:`1px solid ${C.border}`}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:14}}>
              <div style={{fontSize:15,fontWeight:700,color:C.black}}>Top Items</div>
              <div style={{display:"flex",gap:4}}>
                {["today","week"].map(r=>(
                  <button key={r} onClick={()=>setTopRange(r)} style={{padding:"4px 10px",borderRadius:12,border:`1px solid ${topRange===r?C.primary:C.border}`,background:topRange===r?C.primaryPale:"transparent",color:topRange===r?C.primary:C.muted,cursor:"pointer",fontSize:11,fontWeight:700,fontFamily:"Inter,sans-serif"}}>
                    {r==="today"?"Today":"7 Days"}
                  </button>
                ))}
              </div>
            </div>
            {topItems.length===0
              ? <div style={{color:C.muted,fontSize:13}}>No sales yet</div>
              : topItems.map(([name,qty],i)=>(
                <div key={name} style={{display:"flex",alignItems:"center",gap:10,marginBottom:10,paddingBottom:10,borderBottom:`1px solid ${C.border}`}}>
                  <div style={{width:22,height:22,borderRadius:"50%",background:i===0?C.primary:C.faint,display:"flex",alignItems:"center",justifyContent:"center",fontSize:11,fontWeight:800,color:i===0?"#fff":C.muted,flexShrink:0}}>{i+1}</div>
                  <div style={{flex:1,fontSize:13,fontWeight:600,color:C.black,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{name}</div>
                  <Chip color="primary" size="sm">{qty}</Chip>
                </div>
              ))
            }
          </div>
          {lowStock.length>0&&(
            <div style={{background:"#fff5f5",border:`1px solid ${C.red}30`,borderRadius:14,padding:20}}>
              <div style={{fontWeight:700,color:C.red,fontSize:14,marginBottom:10}}>⚠ Low Stock</div>
              {lowStock.map(i=>(
                <div key={i.id} style={{display:"flex",justifyContent:"space-between",marginBottom:6,fontSize:13}}>
                  <span style={{color:C.black}}>{i.name}</span>
                  <span style={{color:C.red,fontWeight:700}}>{i.stock} {i.unit}</span>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  )
}
function POSModule() {
  const business = useBusiness()
  const staff = useStaff()
  const { data: categories } = useData("bb_categories", { active: true })
  const { data: menuItems } = useData("bb_menu_items", { active: true })
  const { data: modGroups } = useData("bb_modifier_groups")
  const { data: modOptions } = useData("bb_modifier_options")
  const { data: itemModLinks } = useData("bb_item_modifiers")
  const { data: openTabs, refresh: refreshTabs } = useData("bb_open_tabs")

  const [activeCat, setActiveCat] = useState("all")
  const [search, setSearch] = useState("")
  const [cart, setCart] = useState([])
  const [orderType, setOrderType] = useState("sit-in")
  const [tableNum, setTableNum] = useState("")
  const [selItem, setSelItem] = useState(null)
  const [selQty, setSelQty] = useState(1)
  const [selections, setSelections] = useState({})
  const [itemNote, setItemNote] = useState("")
  const [checkoutOpen, setCheckoutOpen] = useState(false)
  const [payMethod, setPayMethod] = useState(null)
  const [cashGiven, setCashGiven] = useState("")
  const [splitCard, setSplitCard] = useState("")
  const [splitCash, setSplitCash] = useState("")
  // Discount system
  const [discountType, setDiscountType] = useState("none") // none | percent | fixed | comp
  const [discountPct, setDiscountPct]   = useState(0)
  const [discountFixed, setDiscountFixed] = useState("")
  const [discountReason, setDiscountReason] = useState("")
  const [discountPin, setDiscountPin]   = useState("")
  const [discountPinError, setDiscountPinError] = useState("")
  const [discountPinModal, setDiscountPinModal] = useState(false)
  const [pendingDiscountType, setPendingDiscountType] = useState(null)
  // Legacy alias
  const discount = discountType==="percent"?discountPct:0
  const [tipPct, setTipPct] = useState(0)
  const [customTip, setCustomTip] = useState("")
  const [saving, setSaving] = useState(false)
  const [done, setDone] = useState(false)
  const [lastOrder, setLastOrder] = useState(null)
  const [optMenuOpen, setOptMenuOpen] = useState(false)
  const [tabsOpen, setTabsOpen] = useState(false)
  const [saveTabName, setSaveTabName] = useState("")
  const [activeTabId, setActiveTabId] = useState(null)
  // Loyalty
  const [loyaltyCustomer, setLoyaltyCustomer] = useState(null)
  const [loyaltyModal, setLoyaltyModal] = useState(false)
  const [redeemPoints, setRedeemPoints] = useState(false)
  const {data:loyaltyRules} = useData("bb_loyalty_rules")
  const {data:shifts} = useData("bb_shifts")

  // Filter menu items (including time-of-day availability)
  const filtered = menuItems.filter(item => {
    const catMatch = activeCat === "all" || item.category_id === activeCat
    const searchMatch = !search || item.name.toLowerCase().includes(search.toLowerCase())
    // Time availability check
    if(item.available_from && item.available_to) {
      const now = new Date().toTimeString().slice(0,5)
      const available = now >= item.available_from && now <= item.available_to
      if(!available) return false
    }
    return catMatch && searchMatch
  })

  // Get modifier groups for an item
  const getGroupsForItem = (itemId, catId) => {
    const linkedIds = itemModLinks
      .filter(l => l.item_id === itemId)
      .map(l => l.group_id)
    return modGroups.filter(g => linkedIds.includes(g.id))
      .sort((a, b) => (a.sort_order || 0) - (b.sort_order || 0))
  }

  const getOptionsForGroup = (groupId) =>
    modOptions.filter(o => o.group_id === groupId && o.active !== false)
      .sort((a, b) => (a.sort_order || 0) - (b.sort_order || 0))

  // Open item modal
  const openItem = (item) => {
    const groups = getGroupsForItem(item.id, item.category_id)
    const init = {}
    groups.forEach(g => {
      const opts = getOptionsForGroup(g.id)
      init[g.id] = g.selection_type === "single" && opts.length > 0 ? [opts[0].id] : []
    })
    setSelItem(item)
    setSelections(init)
    setSelQty(1)
    setItemNote("")
  }

  const toggleOption = (group, optId) => {
    setSelections(prev => {
      const cur = prev[group.id] || []
      if (group.selection_type === "single") return { ...prev, [group.id]: [optId] }
      const next = cur.includes(optId) ? cur.filter(i => i !== optId) : [...cur, optId]
      return { ...prev, [group.id]: next }
    })
  }

  const computeExtra = () => {
    let extra = 0
    Object.values(selections).flat().forEach(oid => {
      const opt = modOptions.find(o => o.id === oid)
      if (opt) extra += parseFloat(opt.price_delta || 0)
    })
    return extra
  }

  const addToCart = () => {
    const extra = computeExtra()
    const groups = getGroupsForItem(selItem.id, selItem.category_id)
    const selArr = groups
      .map(g => ({
        groupId: g.id,
        groupName: g.name,
        options: (selections[g.id] || [])
          .map(oid => modOptions.find(o => o.id === oid))
          .filter(Boolean)
          .map(o => ({ id: o.id, label: o.name, price_delta: parseFloat(o.price_delta || 0) }))
      }))
      .filter(s => s.options.length > 0)

    setCart(prev => [...prev, {
      id: uid(),
      itemId: selItem.id,
      name: selItem.name,
      emoji: selItem.emoji || "☕",
      image_url: selItem.image_url,
      price: parseFloat(selItem.price) + extra,
      qty: selQty,
      selections: selArr,
      notes: itemNote,
      category_id: selItem.category_id,
    }])
    setSelItem(null)
  }

  const updQty = (id, delta) =>
    setCart(prev => prev.map(i => i.id === id ? { ...i, qty: Math.max(0, i.qty + delta) } : i).filter(i => i.qty > 0))

  const removeItem = (id) => setCart(prev => prev.filter(i => i.id !== id))

  // Calculations
  const subtotal = cart.reduce((s, i) => s + i.price * i.qty, 0)
  const discAmt = discountType==="comp" ? subtotal
    : discountType==="fixed" ? Math.min(parseFloat(discountFixed)||0, subtotal)
    : discountType==="percent" ? subtotal*(discountPct/100)
    : 0
  const tipAmt = customTip !== "" ? (parseFloat(customTip) || 0) : subtotal * (tipPct / 100)
  // Loyalty redemption: R10 per 100 points
  const loyaltyRule = loyaltyRules[0]
  const pointsValue = redeemPoints && loyaltyCustomer ? Math.min((loyaltyCustomer.loyalty_points||0)/100*10, subtotal-discAmt) : 0
  // VAT calculation
  const vatRate = business?.vat_registered ? parseFloat(business?.vat_rate||15)/100 : 0
  const vatAmt  = (subtotal - discAmt - pointsValue) * vatRate
  const total = Math.max(0, subtotal - discAmt - pointsValue + vatAmt + tipAmt)
  // Points earned this sale (1 point per R1 spent)
  const pointsEarned = Math.floor(total)
  const cashNum = parseFloat(cashGiven) || 0
  const change = Math.max(0, cashNum - total)

  const cashSuggestions = total > 0 ? [...new Set(
    [5, 10, 20, 50].map(r => Math.ceil(total / r) * r).filter(v => v > total)
  )].sort((a, b) => a - b).slice(0, 4) : []

  const splitValid = payMethod === "split"
    ? Math.abs((parseFloat(splitCard) || 0) + (parseFloat(splitCash) || 0) - total) < 0.01
    : true

  const canConfirm = payMethod && !saving &&
    (payMethod !== "cash" || cashNum >= total) &&
    (payMethod !== "split" || splitValid)

  const resetOrder = () => {
    setCart([]); setDiscountType("none"); setDiscountPct(0); setDiscountFixed(""); setDiscountReason("")
    setTipPct(0); setCustomTip(""); setPayMethod(null); setCashGiven(""); setSplitCard(""); setSplitCash("")
    setCheckoutOpen(false); setTableNum(""); setOrderType("sit-in"); setActiveTabId(null)
    setLoyaltyCustomer(null); setRedeemPoints(false)
  }

  const completeOrder = async () => {
    setSaving(true)
    try {
      const order = {
        id: uid(),
        business_id: business.id,
        staff_id: staff?.id,
        staff_name: staff?.name,
        date: new Date().toISOString().slice(0, 10),
        time: new Date().toTimeString().slice(0, 5),
        items: cart.map(i => ({
          name: i.name, qty: i.qty, price: i.price,
          category_id: i.category_id, selections: i.selections, notes: i.notes
        })),
        order_type: orderType,
        table_num: tableNum || null,
        subtotal,
        discount_type: discountType,
        discount_pct: discountType==="percent"?discountPct:0,
        discount_amt: discAmt,
        discount_reason: discountReason||null,
        tip: tipAmt,
        vat_amt: vatAmt,
        total,
        method: payMethod,
        split_card: payMethod === "split" ? parseFloat(splitCard) || 0 : 0,
        split_cash: payMethod === "split" ? parseFloat(splitCash) || 0 : 0,
        cash_given: payMethod === "cash" ? cashNum : 0,
        change_given: payMethod === "cash" ? change : 0,
        status: "completed",
        shift_id: shifts.find(s=>s.status==="open"&&s.date===new Date().toISOString().slice(0,10))?.id||null,
        customer_id: loyaltyCustomer?.id||null,
        customer_name: loyaltyCustomer?.name||null,
      }
      await supabase.from("bb_orders").insert(order)
      if (activeTabId) {
        await supabase.from("bb_open_tabs").delete().eq("id", activeTabId)
        await refreshTabs()
      }
      // Update loyalty points
      if(loyaltyCustomer) {
        const newPoints = (loyaltyCustomer.loyalty_points||0) + pointsEarned - (redeemPoints?loyaltyCustomer.loyalty_points:0)
        await supabase.from("bb_customers").update({
          loyalty_points: Math.max(0, newPoints),
          total_visits: (loyaltyCustomer.total_visits||0)+1,
          total_spent: (parseFloat(loyaltyCustomer.total_spent)||0)+total,
          last_visit: new Date().toISOString(),
        }).eq("id", loyaltyCustomer.id)
        await supabase.from("bb_loyalty_transactions").insert([
          {id:uid(),business_id:business.id,customer_id:loyaltyCustomer.id,order_id:order.id,type:"earn",points:pointsEarned,description:`Earned from order`},
          ...(redeemPoints?[{id:uid(),business_id:business.id,customer_id:loyaltyCustomer.id,order_id:order.id,type:"redeem",points:-(loyaltyCustomer.loyalty_points||0),description:"Redeemed for discount"}]:[])
        ])
      }
      // Auto-print kitchen ticket
      if(BB_PRINTER.connected) {
        try {
          const kitchenBytes = buildKitchenBytes(order, order.items, getKitchenCats())
          if(kitchenBytes) await BB_PRINTER.print(kitchenBytes)
        } catch(e) { console.warn("Kitchen print failed:", e) }
      }
      setLastOrder(order)
      setSaving(false)
      setDone(true)
      setTimeout(() => { setDone(false); resetOrder() }, 4000)
    } catch (e) {
      setSaving(false)
      console.error(e)
    }
  }

  const saveTab = async () => {
    if (!cart.length) return
    const label = saveTabName.trim() || `Tab ${openTabs.length + 1}`
    if (activeTabId) {
      await supabase.from("bb_open_tabs").update({ label, items: cart, order_type: orderType, table_num: tableNum || null }).eq("id", activeTabId)
    } else {
      await supabase.from("bb_open_tabs").insert({
        id: uid(), business_id: business.id, label,
        items: cart, order_type: orderType, table_num: tableNum || null,
        created_by: staff?.id,
      })
    }
    await refreshTabs()
    setTabsOpen(false); setSaveTabName(""); resetOrder()
  }

  const resumeTab = (tab) => {
    const items = typeof tab.items === "string" ? JSON.parse(tab.items) : tab.items || []
    setCart(items.map(i => ({ ...i, id: uid() })))
    setOrderType(tab.order_type || "sit-in")
    setTableNum(tab.table_num || "")
    setActiveTabId(tab.id)
    setTabsOpen(false)
  }

  const deleteTab = async (id) => {
    await supabase.from("bb_open_tabs").delete().eq("id", id)
    await refreshTabs()
  }

  const optMenuItems = [
    { icon: "🗑", label: "Clear ticket", action: () => { resetOrder(); setOptMenuOpen(false) } },
    { icon: "📑", label: "Open tabs", action: () => { setTabsOpen(true); setOptMenuOpen(false) } },
    { icon: "✂️", label: "Save for later", action: () => { setTabsOpen(true); setOptMenuOpen(false) } },
  ]

  const itemPreviewPrice = selItem ? parseFloat(selItem.price) + computeExtra() : 0

  return (
    <div style={{ display: "flex", height: "100%", overflow: "hidden", background: C.bg }}>
      {/* ── LEFT: Menu ── */}
      {!checkoutOpen && (
        <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", borderRight: `1px solid ${C.border}` }}>
          {/* Search + Categories */}
          <div style={{ padding: "12px 16px", background: C.surface, borderBottom: `1px solid ${C.border}` }}>
            <input
              value={search} onChange={e => setSearch(e.target.value)}
              placeholder="Search menu…"
              style={{ width: "100%", background: C.faint, border: `1px solid ${C.border}`, borderRadius: 8, color: C.black, padding: "10px 14px", fontSize: 14, fontFamily: "Inter,sans-serif", outline: "none", boxSizing: "border-box" }}
            />
          </div>
          <div style={{ display: "flex", gap: 6, padding: "10px 16px", overflowX: "auto", background: C.surface, borderBottom: `1px solid ${C.border}`, flexShrink: 0 }}>
            {[{ id: "all", name: "All Items" }, ...categories].map(cat => (
              <button key={cat.id} onClick={() => setActiveCat(cat.id)}
                style={{ padding: "8px 16px", borderRadius: 20, border: "none", cursor: "pointer", whiteSpace: "nowrap", fontFamily: "Inter,sans-serif", fontWeight: 600, fontSize: 13, flexShrink: 0, transition: "all 0.15s", background: activeCat === cat.id ? C.primary : C.faint, color: activeCat === cat.id ? "#fff" : C.muted }}>
                {cat.emoji && cat.id !== "all" ? `${cat.emoji} ` : ""}{cat.name}
              </button>
            ))}
          </div>

          {/* Item grid */}
          <div style={{ flex: 1, overflowY: "auto", padding: 12, display: "grid", gridTemplateColumns: "repeat(auto-fill,minmax(150px,1fr))", gap: 10, alignContent: "start" }}>
            {filtered.map(item => (
              <button key={item.id} onClick={() => openItem(item)}
                style={{ background: C.surface, border: `1px solid ${C.border}`, borderRadius: 12, padding: 0, cursor: "pointer", textAlign: "left", overflow: "hidden", transition: "all 0.15s", fontFamily: "Inter,sans-serif", display: "flex", flexDirection: "column" }}
                onMouseEnter={e => { e.currentTarget.style.transform = "translateY(-2px)"; e.currentTarget.style.boxShadow = "0 4px 12px rgba(0,0,0,.08)" }}
                onMouseLeave={e => { e.currentTarget.style.transform = ""; e.currentTarget.style.boxShadow = "" }}>
                {/* Image or emoji */}
                <div style={{ height: 90, background: C.faint, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 36, overflow: "hidden" }}>
                  {item.image_url
                    ? <img src={item.image_url} alt={item.name} style={{ width: "100%", height: "100%", objectFit: "cover" }} />
                    : item.emoji || "☕"}
                </div>
                <div style={{ padding: "10px 12px 12px" }}>
                  <div style={{ fontSize: 13, fontWeight: 600, color: C.black, lineHeight: 1.3, marginBottom: 4 }}>{item.name}</div>
                  <div style={{ fontSize: 14, fontWeight: 700, color: C.primary }}>{fmt(item.price)}</div>
                  {item.track_stock && <div style={{ fontSize: 11, color: parseFloat(item.stock) < 5 ? C.red : C.light, marginTop: 2 }}>{item.stock} left</div>}
                </div>
              </button>
            ))}
            {filtered.length === 0 && (
              <div style={{ gridColumn: "1/-1" }}>
                <Empty icon="🔍" title="No items found" message="Try a different search or category"/>
              </div>
            )}
          </div>
        </div>
      )}

      {/* ── RIGHT: Ticket ── */}
      <div style={{ width: checkoutOpen ? "100%" : 320, display: "flex", flexDirection: "column", background: C.surface, flexShrink: 0, overflow: "hidden" }}>
        {/* Ticket header */}
        <div style={{ padding: "14px 16px", borderBottom: `1px solid ${C.border}`, background: "#fff" }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10 }}>
            {checkoutOpen
              ? <button onClick={() => setCheckoutOpen(false)} style={{ background: "none", border: "none", color: C.primary, cursor: "pointer", fontSize: 14, fontWeight: 600, padding: 0, display: "flex", alignItems: "center", gap: 4 }}>← Back</button>
              : <div style={{ fontSize: 16, fontWeight: 700, color: C.black }}>Ticket {activeTabId && <Chip color="amber" size="sm">Saved tab</Chip>}</div>
            }
            {!checkoutOpen && (
              <div style={{ position: "relative" }}>
                <button onClick={() => setOptMenuOpen(p => !p)} style={{ background: "none", border: `1px solid ${C.border}`, borderRadius: 8, cursor: "pointer", padding: "6px 10px", fontSize: 18, color: C.muted }}>⋮</button>
                {optMenuOpen && (
                  <div style={{ position: "absolute", top: 36, right: 0, background: "#fff", border: `1px solid ${C.border}`, borderRadius: 10, boxShadow: "0 6px 24px rgba(0,0,0,.1)", width: 180, zIndex: 50, overflow: "hidden" }}>
                    {optMenuItems.map(({ icon, label, action }) => (
                      <button key={label} onClick={action} style={{ display: "flex", alignItems: "center", gap: 10, width: "100%", padding: "12px 14px", background: "none", border: "none", borderBottom: `1px solid ${C.border}`, cursor: "pointer", fontSize: 14, color: C.black, fontFamily: "Inter,sans-serif", textAlign: "left" }}>
                        <span>{icon}</span>{label}
                      </button>
                    ))}
                  </div>
                )}
              </div>
            )}
          </div>
          {!checkoutOpen && (
            <div style={{ display: "flex", gap: 8 }}>
              <select value={orderType} onChange={e => setOrderType(e.target.value)}
                style={{ flex: 1, background: C.faint, border: `1px solid ${C.border}`, borderRadius: 8, color: C.black, padding: "8px 10px", fontSize: 13, fontFamily: "Inter,sans-serif" }}>
                <option value="sit-in">Sit-in</option>
                <option value="takeaway">Takeaway</option>
                <option value="delivery">Delivery</option>
              </select>
              {orderType === "sit-in" && (
                <input value={tableNum} onChange={e => setTableNum(e.target.value)} placeholder="Table #"
                  style={{ width: 70, background: C.faint, border: `1px solid ${C.border}`, borderRadius: 8, color: C.black, padding: "8px 10px", fontSize: 13, fontFamily: "Inter,sans-serif", outline: "none" }}/>
              )}
            </div>
          )}
          <div style={{ fontSize: 12, color: C.light, marginTop: 6 }}>{staff?.name} · {cart.length} item{cart.length !== 1 ? "s" : ""}</div>
        </div>

        {/* Cart items */}
        <div style={{ flex: 1, overflowY: "auto", padding: "12px 14px" }} onClick={() => setOptMenuOpen(false)}>
          {cart.length === 0 && !checkoutOpen && (
            <Empty icon="🛒" title="Empty ticket" message="Tap items on the left to add them"/>
          )}
          {cart.map(item => (
            <div key={item.id} style={{ background: "#fff", border: `1px solid ${C.border}`, borderRadius: 10, padding: "12px 14px", marginBottom: 8 }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
                <div style={{ fontSize: 14, fontWeight: 600, color: C.black, flex: 1 }}>{item.name}</div>
                <div style={{ fontSize: 14, fontWeight: 700, color: C.primary, marginLeft: 8, whiteSpace: "nowrap" }}>{fmt(item.price * item.qty)}</div>
              </div>
              {item.selections?.map(s => (
                <div key={s.groupId} style={{ fontSize: 12, color: C.muted, marginTop: 2 }}>
                  {s.groupName}: {s.options.map(o => o.label + (o.price_delta > 0 ? ` +${fmt(o.price_delta)}` : "")).join(", ")}
                </div>
              ))}
              {item.notes && <div style={{ fontSize: 12, color: C.amber, marginTop: 2 }}>📝 {item.notes}</div>}
              {!checkoutOpen && (
                <div style={{ display: "flex", alignItems: "center", gap: 8, marginTop: 10 }}>
                  <button onClick={() => updQty(item.id, -1)} style={{ width: 28, height: 28, borderRadius: "50%", border: `1px solid ${C.border}`, background: C.faint, color: C.muted, cursor: "pointer", fontSize: 16, lineHeight: 1 }}>−</button>
                  <span style={{ fontSize: 14, fontWeight: 700, color: C.black, minWidth: 20, textAlign: "center" }}>{item.qty}</span>
                  <button onClick={() => updQty(item.id, 1)} style={{ width: 28, height: 28, borderRadius: "50%", border: `1px solid ${C.border}`, background: C.faint, color: C.muted, cursor: "pointer", fontSize: 16, lineHeight: 1 }}>+</button>
                  <button onClick={() => removeItem(item.id)} style={{ marginLeft: "auto", background: "none", border: "none", color: C.red, cursor: "pointer", fontSize: 18 }}>×</button>
                </div>
              )}
            </div>
          ))}
        </div>

        {/* Footer: totals + charge */}
        {cart.length > 0 && (
          <div style={{ borderTop: `1px solid ${C.border}`, padding: "14px 16px", background: "#fff" }}>
            {done ? (
              <div style={{ textAlign: "center", padding: "16px 0" }}>
                <div style={{ fontSize: 48 }}>✅</div>
                <div style={{ fontSize: 18, fontWeight: 700, color: C.primary, marginTop: 8 }}>Sale Complete!</div>
                {payMethod === "cash" && change > 0 && (
                  <div style={{ marginTop: 10, background: C.greenPale, borderRadius: 10, padding: "12px 16px" }}>
                    <div style={{ fontSize: 12, color: C.muted }}>Change due</div>
                    <div style={{ fontSize: 24, fontWeight: 800, color: C.green }}>{fmt(change)}</div>
                  </div>
                )}
                {lastOrder && BB_PRINTER.connected && (
                  <button onClick={async()=>{
                    try {
                      const bytes = buildReceiptBytes(lastOrder, lastOrder.items, getReceiptSettings())
                      await BB_PRINTER.print(bytes)
                    } catch(e){ alert("Print failed: "+e.message) }
                  }} style={{marginTop:12,width:"100%",padding:"12px",borderRadius:10,border:`1px solid ${C.border}`,background:C.faint,color:C.black,cursor:"pointer",fontSize:14,fontWeight:600,fontFamily:"Inter,sans-serif",display:"flex",alignItems:"center",justifyContent:"center",gap:8}}>
                    🖨 Print Receipt
                  </button>
                )}
                {lastOrder && !BB_PRINTER.connected && (
                  <div style={{marginTop:10,fontSize:12,color:C.muted}}>Connect printer in Printer settings to print receipts</div>
                )}
              </div>
            ) : !checkoutOpen ? (
              <>
                <div style={{ display: "flex", justifyContent: "space-between", fontSize: 13, color: C.muted, marginBottom: 4 }}><span>Subtotal</span><span>{fmt(subtotal)}</span></div>
                {discAmt > 0 && <div style={{ display: "flex", justifyContent: "space-between", fontSize: 13, color: C.green, marginBottom: 4 }}><span>{discountType==="comp"?"Complimentary":discountType==="fixed"?"Discount":discountType==="percent"?`Discount ${discountPct}%`:"Discount"}</span><span>−{fmt(discAmt)}</span></div>}
                {pointsValue > 0 && <div style={{ display: "flex", justifyContent: "space-between", fontSize: 13, color: C.amber, marginBottom: 4 }}><span>🎯 Loyalty Redemption</span><span>−{fmt(pointsValue)}</span></div>}
                {vatAmt > 0 && <div style={{ display: "flex", justifyContent: "space-between", fontSize: 13, color: C.muted, marginBottom: 4 }}><span>VAT ({business?.vat_rate||15}%)</span><span>+{fmt(vatAmt)}</span></div>}
                {tipAmt > 0 && <div style={{ display: "flex", justifyContent: "space-between", fontSize: 13, color: C.amber, marginBottom: 4 }}><span>Tip</span><span>+{fmt(tipAmt)}</span></div>}
                {loyaltyCustomer && <div style={{ display: "flex", justifyContent: "space-between", fontSize: 12, color: C.primary, marginBottom: 4 }}><span>🎯 {loyaltyCustomer.name}</span><span>+{pointsEarned}pts</span></div>}
                <div style={{ display: "flex", justifyContent: "space-between", fontSize: 18, fontWeight: 800, color: C.black, borderTop: `1px solid ${C.border}`, paddingTop: 10, marginTop: 4, marginBottom: 12 }}><span>Total</span><span style={{ color: C.primary }}>{fmt(total)}</span></div>
                <Btn size="lg" onClick={() => setCheckoutOpen(true)} style={{ width: "100%" }}>Charge · {fmt(total)}</Btn>
                <div style={{ display: "flex", gap: 8, marginTop: 8 }}>
                  <Btn variant="secondary" size="sm" onClick={() => setTabsOpen(true)} style={{ flex: 1 }}>Save</Btn>
                  <Btn variant="ghost" size="sm" onClick={resetOrder} style={{ flex: 1 }}>Clear</Btn>
                </div>
              </>
            ) : (
              /* CHECKOUT PANEL */
              <div style={{ display: "flex", flexDirection: "column", gap: 14, maxWidth: 440, margin: "0 auto" }}>
                <div style={{ textAlign: "center", paddingBottom: 8 }}>
                  <div style={{ fontSize: 36, fontWeight: 800, color: C.black, fontFamily: "Playfair Display,serif" }}>{fmt(total)}</div>
                  <div style={{ fontSize: 13, color: C.muted }}>Total amount due</div>
                </div>

                {/* Discount & Comp System */}
                <div>
                  <div style={{fontSize:12,color:C.muted,fontWeight:600,textTransform:"uppercase",letterSpacing:0.8,marginBottom:8}}>Discount / Complimentary</div>
                  <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr 1fr",gap:6,marginBottom:8}}>
                    {[["none","None",""],["percent","%",""],["fixed","R Off",""],["comp","Comp","🎁"]].map(([type,label,icon])=>(
                      <button key={type} onClick={()=>{
                        if(type!=="none"&&staff?.role==="barista"){
                          setPendingDiscountType(type); setDiscountPin(""); setDiscountPinError(""); setDiscountPinModal(true)
                        } else {
                          setDiscountType(type); setDiscountPct(0); setDiscountFixed("")
                        }
                      }}
                        style={{padding:"10px 4px",borderRadius:8,border:"1px solid",borderColor:discountType===type?C.primary:C.border,background:discountType===type?C.primaryPale:C.faint,color:discountType===type?C.primary:C.muted,fontSize:13,fontWeight:600,cursor:"pointer",fontFamily:"Inter,sans-serif"}}>
                        {icon} {label}
                      </button>
                    ))}
                  </div>
                  {discountType==="percent"&&(
                    <div style={{display:"flex",gap:6,marginBottom:8}}>
                      {[5,10,15,20,25,50].map(d=>(
                        <button key={d} onClick={()=>setDiscountPct(d)}
                          style={{flex:1,padding:"8px 4px",borderRadius:8,border:"1px solid",borderColor:discountPct===d?C.primary:C.border,background:discountPct===d?C.primaryPale:C.faint,color:discountPct===d?C.primary:C.muted,fontSize:12,fontWeight:600,cursor:"pointer",fontFamily:"Inter,sans-serif"}}>
                          {d}%
                        </button>
                      ))}
                    </div>
                  )}
                  {discountType==="fixed"&&(
                    <input type="number" value={discountFixed} onChange={e=>setDiscountFixed(e.target.value)} placeholder="Discount amount (R)"
                      style={{width:"100%",background:C.faint,border:`1px solid ${C.border}`,borderRadius:8,color:C.black,padding:"10px 12px",fontSize:14,fontFamily:"Inter,sans-serif",outline:"none",boxSizing:"border-box",marginBottom:8}}/>
                  )}
                  {discountType==="comp"&&(
                    <div style={{background:C.amberPale,border:`1px solid ${C.amber}40`,borderRadius:8,padding:"8px 12px",fontSize:13,color:C.amber,fontWeight:600,marginBottom:8}}>
                      🎁 Complimentary — full order is free
                    </div>
                  )}
                  {discountType!=="none"&&(
                    <input value={discountReason} onChange={e=>setDiscountReason(e.target.value)} placeholder="Reason for discount (required)"
                      style={{width:"100%",background:C.faint,border:`1px solid ${C.border}`,borderRadius:8,color:C.black,padding:"10px 12px",fontSize:14,fontFamily:"Inter,sans-serif",outline:"none",boxSizing:"border-box"}}/>
                  )}
                  {discAmt>0&&<div style={{fontSize:13,color:C.green,fontWeight:600,marginTop:6}}>Saving: {fmt(discAmt)}</div>}
                </div>

                {/* Tip */}
                <div>
                  <div style={{ fontSize: 12, color: C.muted, fontWeight: 600, textTransform: "uppercase", letterSpacing: 0.8, marginBottom: 6 }}>Tip</div>
                  <div style={{ display: "flex", gap: 6, marginBottom: 6 }}>
                    {[0, 10, 15, 20].map(p => {
                      const isSel = customTip === "" && tipPct === p
                      return (
                        <button key={p} onClick={() => { setTipPct(p); setCustomTip("") }}
                          style={{ flex: 1, padding: "8px 4px", borderRadius: 8, border: "1px solid", borderColor: isSel ? C.primary : C.border, background: isSel ? C.primaryPale : C.faint, color: isSel ? C.primary : C.muted, fontSize: 13, fontWeight: 600, cursor: "pointer", fontFamily: "Inter,sans-serif" }}>
                          {p === 0 ? "None" : `${p}%`}
                        </button>
                      )
                    })}
                  </div>
                  <input type="number" value={customTip} onChange={e => { setCustomTip(e.target.value); setTipPct(0) }} placeholder="Custom tip (R)"
                    style={{ width: "100%", background: C.faint, border: `1px solid ${C.border}`, borderRadius: 8, color: C.black, padding: "8px 12px", fontSize: 14, fontFamily: "Inter,sans-serif", outline: "none", boxSizing: "border-box" }}/>
                </div>

                {/* Loyalty */}
                <div>
                  <div style={{fontSize:12,color:C.muted,fontWeight:600,textTransform:"uppercase",letterSpacing:0.8,marginBottom:8}}>Loyalty Programme</div>
                  {loyaltyCustomer?(
                    <div style={{background:C.amberPale,border:`1px solid ${C.amber}40`,borderRadius:10,padding:"12px 14px"}}>
                      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8}}>
                        <div>
                          <div style={{fontSize:14,fontWeight:700,color:C.black}}>{loyaltyCustomer.name}</div>
                          <div style={{fontSize:12,color:C.muted}}>{loyaltyCustomer.loyalty_points||0} points · {loyaltyCustomer.total_visits||0} visits</div>
                        </div>
                        <button onClick={()=>setLoyaltyCustomer(null)} style={{background:"none",border:"none",color:C.muted,cursor:"pointer",fontSize:16}}>×</button>
                      </div>
                      <div style={{fontSize:13,color:C.primary,marginBottom:8}}>+{pointsEarned} points earned on this sale</div>
                      {(loyaltyCustomer.loyalty_points||0)>=100&&(
                        <div onClick={()=>setRedeemPoints(!redeemPoints)} style={{display:"flex",alignItems:"center",gap:10,padding:"8px 12px",background:redeemPoints?C.primaryPale:C.faint,border:`1px solid ${redeemPoints?C.primary:C.border}`,borderRadius:8,cursor:"pointer"}}>
                          <div style={{width:18,height:18,borderRadius:4,border:`2px solid ${redeemPoints?C.primary:C.border}`,background:redeemPoints?C.primary:"transparent",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>
                            {redeemPoints&&<span style={{color:"#fff",fontSize:11}}>✓</span>}
                          </div>
                          <span style={{fontSize:13,fontWeight:600,color:redeemPoints?C.primary:C.black}}>
                            Redeem {loyaltyCustomer.loyalty_points} points → save {fmt(Math.min((loyaltyCustomer.loyalty_points/100)*10,subtotal-discAmt))}
                          </span>
                        </div>
                      )}
                    </div>
                  ):(
                    <button onClick={()=>setLoyaltyModal(true)} style={{width:"100%",padding:"12px 14px",borderRadius:10,border:`1px dashed ${C.border}`,background:C.faint,color:C.muted,cursor:"pointer",fontSize:14,fontFamily:"Inter,sans-serif",fontWeight:500,display:"flex",alignItems:"center",justifyContent:"center",gap:8}}>
                      🎯 Link Customer for Loyalty Points
                    </button>
                  )}
                </div>

                {/* Payment methods */}
                <div>
                  <div style={{ fontSize: 12, color: C.muted, fontWeight: 600, textTransform: "uppercase", letterSpacing: 0.8, marginBottom: 6 }}>Payment Method</div>
                  <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
                    {[["card","💳","Card"],["cash","💵","Cash"],["eft","🏦","EFT"],["split","🔀","Split"]].map(([m, icon, label]) => (
                      <button key={m} onClick={() => setPayMethod(m)}
                        style={{ padding: "14px 16px", borderRadius: 10, border: "1px solid", borderColor: payMethod === m ? C.primary : C.border, background: payMethod === m ? C.primaryPale : "#fff", color: payMethod === m ? C.primary : C.black, fontSize: 15, fontWeight: 600, cursor: "pointer", fontFamily: "Inter,sans-serif", display: "flex", alignItems: "center", gap: 10, textAlign: "left" }}>
                        <span style={{ fontSize: 20 }}>{icon}</span>{label}
                      </button>
                    ))}
                  </div>
                </div>

                {/* Cash input */}
                {payMethod === "cash" && (
                  <div style={{ background: C.faint, borderRadius: 10, padding: "14px" }}>
                    <div style={{ fontSize: 12, color: C.muted, fontWeight: 600, marginBottom: 8 }}>Cash received</div>
                    <div style={{ display: "flex", gap: 6, marginBottom: 8 }}>
                      {cashSuggestions.map(v => (
                        <button key={v} onClick={() => setCashGiven(String(v))}
                          style={{ flex: 1, padding: "10px 4px", borderRadius: 8, border: "1px solid", borderColor: cashNum === v ? C.primary : C.border, background: cashNum === v ? C.primaryPale : "#fff", color: cashNum === v ? C.primary : C.black, fontSize: 14, fontWeight: 700, cursor: "pointer", fontFamily: "Inter,sans-serif" }}>
                          R{v}
                        </button>
                      ))}
                    </div>
                    <input type="number" value={cashGiven} onChange={e => setCashGiven(e.target.value)} placeholder="Enter amount" autoFocus
                      style={{ width: "100%", background: "#fff", border: `1px solid ${C.border}`, borderRadius: 8, color: C.black, padding: "12px 14px", fontSize: 16, fontFamily: "Inter,sans-serif", outline: "none", boxSizing: "border-box" }}/>
                    {cashNum > 0 && (
                      <div style={{ marginTop: 8, fontSize: 16, fontWeight: 700, color: cashNum >= total ? C.green : C.red, display: "flex", justifyContent: "space-between" }}>
                        <span>{cashNum >= total ? "Change" : "Short"}</span>
                        <span>{fmt(Math.abs(cashNum - total))}</span>
                      </div>
                    )}
                  </div>
                )}

                {/* Split input */}
                {payMethod === "split" && (
                  <div style={{ background: C.faint, borderRadius: 10, padding: "14px" }}>
                    <div style={{ fontSize: 12, color: C.muted, fontWeight: 600, marginBottom: 10 }}>Split breakdown (must total {fmt(total)})</div>
                    <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
                      <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                        <span style={{ fontSize: 18 }}>💳</span>
                        <input type="number" value={splitCard} onChange={e => setSplitCard(e.target.value)} placeholder="Card amount"
                          style={{ flex: 1, background: "#fff", border: `1px solid ${C.border}`, borderRadius: 8, color: C.black, padding: "10px 12px", fontSize: 14, fontFamily: "Inter,sans-serif", outline: "none" }}/>
                      </div>
                      <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                        <span style={{ fontSize: 18 }}>💵</span>
                        <input type="number" value={splitCash} onChange={e => setSplitCash(e.target.value)} placeholder="Cash amount"
                          style={{ flex: 1, background: "#fff", border: `1px solid ${C.border}`, borderRadius: 8, color: C.black, padding: "10px 12px", fontSize: 14, fontFamily: "Inter,sans-serif", outline: "none" }}/>
                      </div>
                      {(parseFloat(splitCard) || 0) + (parseFloat(splitCash) || 0) > 0 && (
                        <div style={{ fontSize: 13, fontWeight: 700, color: splitValid ? C.green : C.red }}>
                          {splitValid ? "✓ Amounts balance" : `⚠ Doesn't add up to ${fmt(total)}`}
                        </div>
                      )}
                    </div>
                  </div>
                )}

                <Btn size="lg" onClick={completeOrder} disabled={!canConfirm} style={{ width: "100%" }}>
                  {saving ? "Processing…" : `Confirm · ${fmt(total)}`}
                </Btn>
              </div>
            )}
          </div>
        )}
      </div>

      {/* ── MODIFIER MODAL ── */}
      {selItem && (
        <Modal title={`${selItem.name}`} subtitle={fmt(itemPreviewPrice)} onClose={() => setSelItem(null)} width={460}>
          <div style={{ display: "flex", flexDirection: "column", gap: 18 }}>
            {getGroupsForItem(selItem.id, selItem.category_id).map(group => {
              const opts = getOptionsForGroup(group.id)
              const sel = selections[group.id] || []
              return (
                <div key={group.id}>
                  <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 8 }}>
                    <span style={{ fontSize: 13, fontWeight: 700, color: C.black, textTransform: "uppercase", letterSpacing: 0.5 }}>{group.name}</span>
                    <span style={{ fontSize: 11, color: C.light }}>
                      {group.required ? "Required · " : ""}{group.selection_type === "single" ? "Choose one" : "Choose any"}
                    </span>
                  </div>
                  <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8 }}>
                    {opts.map(opt => {
                      const isSel = sel.includes(opt.id)
                      return (
                        <button key={opt.id} onClick={() => toggleOption(group, opt)}
                          style={{ padding: "12px 14px", borderRadius: 10, border: "1px solid", borderColor: isSel ? C.primary : C.border, background: isSel ? C.primaryPale : C.faint, color: isSel ? C.primary : C.black, cursor: "pointer", fontFamily: "Inter,sans-serif", display: "flex", justifyContent: "space-between", alignItems: "center", fontSize: 14, fontWeight: isSel ? 600 : 400 }}>
                          <span>{opt.name}</span>
                          {parseFloat(opt.price_delta || 0) > 0 && <span style={{ fontSize: 12, fontWeight: 600 }}>+{fmt(opt.price_delta)}</span>}
                        </button>
                      )
                    })}
                  </div>
                </div>
              )
            })}

            {/* Quantity */}
            <div>
              <div style={{ fontSize: 13, fontWeight: 700, color: C.black, textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 8 }}>Quantity</div>
              <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 20, background: C.faint, borderRadius: 10, padding: "12px 0" }}>
                <button onClick={() => setSelQty(q => Math.max(1, q - 1))}
                  style={{ width: 36, height: 36, borderRadius: "50%", border: `1px solid ${C.border}`, background: "#fff", cursor: "pointer", fontSize: 20, color: C.muted }}>−</button>
                <span style={{ fontSize: 22, fontWeight: 700, color: C.black, minWidth: 32, textAlign: "center" }}>{selQty}</span>
                <button onClick={() => setSelQty(q => q + 1)}
                  style={{ width: 36, height: 36, borderRadius: "50%", border: `1px solid ${C.border}`, background: "#fff", cursor: "pointer", fontSize: 20, color: C.muted }}>+</button>
              </div>
            </div>

            {/* Comment */}
            <div>
              <div style={{ fontSize: 13, fontWeight: 700, color: C.black, textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 8 }}>Comment</div>
              <textarea value={itemNote} onChange={e => setItemNote(e.target.value)} placeholder="e.g. extra hot, no onion, allergy note…"
                style={{ width: "100%", background: C.faint, border: `1px solid ${C.border}`, borderRadius: 10, color: C.black, padding: "12px 14px", fontSize: 14, fontFamily: "Inter,sans-serif", resize: "vertical", minHeight: 70, outline: "none", boxSizing: "border-box" }}/>
            </div>

            <div style={{ display: "flex", gap: 10 }}>
              <Btn variant="secondary" onClick={() => setSelItem(null)} style={{ flex: 1 }} size="lg">Cancel</Btn>
              <Btn onClick={addToCart} style={{ flex: 2 }} size="lg">Add · {fmt(itemPreviewPrice * selQty)}</Btn>
            </div>
          </div>
        </Modal>
      )}

      {/* ── LOYALTY LOOKUP MODAL ── */}
      {loyaltyModal&&<LoyaltyLookupModal business={business} onSelect={c=>{setLoyaltyCustomer(c);setRedeemPoints(false)}} onClose={()=>setLoyaltyModal(false)}/>}

      {/* ── DISCOUNT PIN MODAL (for baristas needing manager approval) ── */}
      {discountPinModal&&(
        <Modal title="Manager Approval Required" subtitle="Discounts require a manager or owner PIN" onClose={()=>setDiscountPinModal(false)} width={380}>
          <div style={{display:"flex",flexDirection:"column",gap:14}}>
            <Input label="Manager PIN" type="password" value={discountPin} onChange={e=>{setDiscountPin(e.target.value.slice(0,4));setDiscountPinError("")}} placeholder="••••"/>
            {discountPinError&&<div style={{color:C.red,fontSize:13,fontWeight:600}}>{discountPinError}</div>}
            <Btn size="lg" onClick={async()=>{
              // Check PIN against managers/owners
              const {data:managers} = await supabase.from("bb_staff").select("*").eq("business_id",business.id).in("role",["owner","manager"])
              const match = managers?.find(m=>String(m.pin)===String(discountPin))
              if(!match){ setDiscountPinError("Incorrect PIN — manager or owner PIN required"); return }
              setDiscountType(pendingDiscountType)
              setDiscountPct(0); setDiscountFixed("")
              setDiscountPinModal(false)
            }} disabled={discountPin.length<4}>Approve Discount</Btn>
          </div>
        </Modal>
      )}

      {/* ── OPEN TABS MODAL ── */}
      {tabsOpen && (
        <Modal title="Open Tabs" onClose={() => setTabsOpen(false)} width={480}>
          <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
            {cart.length > 0 && (
              <div style={{ background: C.faint, borderRadius: 10, padding: 14 }}>
                <div style={{ fontSize: 13, color: C.muted, fontWeight: 600, marginBottom: 8 }}>
                  {activeTabId ? "Update saved tab" : "Save current order"}
                </div>
                <div style={{ display: "flex", gap: 8 }}>
                  <input value={saveTabName} onChange={e => setSaveTabName(e.target.value)} placeholder="Customer name or table…"
                    style={{ flex: 1, background: "#fff", border: `1px solid ${C.border}`, borderRadius: 8, color: C.black, padding: "10px 12px", fontSize: 14, fontFamily: "Inter,sans-serif", outline: "none" }}/>
                  <Btn onClick={saveTab}>Save</Btn>
                </div>
              </div>
            )}
            <div>
              <div style={{ fontSize: 13, color: C.muted, fontWeight: 600, marginBottom: 10 }}>Saved Tabs</div>
              {openTabs.length === 0
                ? <Empty icon="📑" title="No open tabs" message="Saved orders will appear here"/>
                : openTabs.map(tab => {
                  const items = typeof tab.items === "string" ? JSON.parse(tab.items) : tab.items || []
                  const tabTotal = items.reduce((s, i) => s + (i.price || 0) * (i.qty || 1), 0)
                  return (
                    <div key={tab.id} style={{ display: "flex", alignItems: "center", gap: 10, background: "#fff", border: `1px solid ${C.border}`, borderRadius: 10, padding: "12px 14px", marginBottom: 8 }}>
                      <div style={{ flex: 1 }}>
                        <div style={{ fontSize: 15, fontWeight: 600, color: C.black }}>{tab.label}</div>
                        <div style={{ fontSize: 12, color: C.muted }}>{items.length} items · {fmt(tabTotal)} · {tab.order_type}</div>
                      </div>
                      <Btn size="sm" onClick={() => resumeTab(tab)}>Resume</Btn>
                      <button onClick={() => deleteTab(tab.id)} style={{ background: "none", border: "none", color: C.red, cursor: "pointer", fontSize: 18 }}>×</button>
                    </div>
                  )
                })
              }
            </div>
          </div>
        </Modal>
      )}
    </div>
  )
}
// ══════════════════════════════════════════════════════════════════════════════
// ORDERS HISTORY
// ══════════════════════════════════════════════════════════════════════════════
function OrdersModule() {
  const business = useBusiness()
  const {data:orders,refresh} = useData("bb_orders")
  const {data:staffList}      = useData("bb_staff")
  const [view,setView]        = useState(null)
  const [search,setSearch]    = useState("")
  const [dateFrom,setDateFrom]= useState(new Date().toISOString().slice(0,10))
  const [dateTo,setDateTo]    = useState(new Date().toISOString().slice(0,10))
  const [refundPin,setRefundPin]   = useState("")
  const [refunding,setRefunding]   = useState(false)
  const [refundError,setRefundError] = useState("")

  const filtered = orders.filter(o=>{
    const matchDate   = o.date>=dateFrom && o.date<=dateTo
    const items = typeof o.items==="string"?JSON.parse(o.items||"[]"):o.items||[]
    const matchSearch = !search
      ||(o.staff_name||"").toLowerCase().includes(search.toLowerCase())
      ||(o.customer_name||"").toLowerCase().includes(search.toLowerCase())
      ||String(o.id).includes(search)
      ||items.some(i=>(i.name||"").toLowerCase().includes(search.toLowerCase()))
      ||(o.method||"").includes(search.toLowerCase())
    return matchDate && matchSearch
  })
  const totalRev = filtered.filter(o=>o.status!=="refunded").reduce((s,o)=>s+parseFloat(o.total||0),0)

  const doRefund = async () => {
    const manager = staffList.find(s=>["owner","manager"].includes(s.role)&&String(s.pin)===String(refundPin))
    if(!manager){ setRefundError("Incorrect manager PIN"); return }
    setRefunding(true)
    await supabase.from("bb_orders").update({status:"refunded",refunded:true,refunded_at:new Date().toISOString(),refunded_by:manager.name}).eq("id",view.id)
    await refresh(); setRefunding(false); setView(null)
  }

  return (
    <div style={{padding:24,display:"flex",flexDirection:"column",gap:16}}>
      <div style={{display:"flex",gap:12,alignItems:"center",flexWrap:"wrap"}}>
        <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search staff, customer, item, method…"
          style={{flex:1,minWidth:200,background:C.surface,border:`1px solid ${C.border}`,borderRadius:8,color:C.black,padding:"10px 14px",fontSize:14,fontFamily:"Inter,sans-serif",outline:"none"}}/>
        <input type="date" value={dateFrom} onChange={e=>setDateFrom(e.target.value)} style={{background:C.surface,border:`1px solid ${C.border}`,borderRadius:8,color:C.black,padding:"10px 12px",fontSize:14,fontFamily:"Inter,sans-serif",outline:"none"}}/>
        <span style={{color:C.muted}}>to</span>
        <input type="date" value={dateTo} onChange={e=>setDateTo(e.target.value)} style={{background:C.surface,border:`1px solid ${C.border}`,borderRadius:8,color:C.black,padding:"10px 12px",fontSize:14,fontFamily:"Inter,sans-serif",outline:"none"}}/>
      </div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(140px,1fr))",gap:12}}>
        <KPI label="Orders" value={filtered.filter(o=>o.status!=="refunded").length} icon="🧾"/>
        <KPI label="Revenue" value={fmt(totalRev)} color={C.primary} icon="💰"/>
        <KPI label="Refunds" value={filtered.filter(o=>o.status==="refunded").length} color={C.red} icon="↩"/>
      </div>
      <div style={{background:C.surface,borderRadius:14,border:`1px solid ${C.border}`,overflow:"hidden"}}>
        {filtered.length===0
          ? <Empty icon="📋" title="No orders found" message="Try adjusting the date range or search"/>
          : <div style={{overflowX:"auto"}}>
              <table style={{width:"100%",borderCollapse:"collapse",minWidth:700}}>
                <thead><tr style={{borderBottom:`2px solid ${C.border}`,background:C.faint}}>
                  {["Date","Time","Staff","Customer","Items","Method","Table","Total","Status",""].map(h=>(
                    <th key={h} style={{padding:"12px 14px",textAlign:"left",fontSize:11,color:C.muted,fontWeight:700,textTransform:"uppercase",whiteSpace:"nowrap"}}>{h}</th>
                  ))}
                </tr></thead>
                <tbody>
                  {filtered.map(o=>{
                    const items=typeof o.items==="string"?JSON.parse(o.items||"[]"):o.items||[]
                    return(
                      <tr key={o.id} style={{borderBottom:`1px solid ${C.border}`,opacity:o.status==="refunded"?0.5:1}}>
                        <td style={{padding:"12px 14px",fontSize:13,color:C.muted,whiteSpace:"nowrap"}}>{o.date}</td>
                        <td style={{padding:"12px 14px",fontSize:13,color:C.muted,whiteSpace:"nowrap"}}>{String(o.time||"").slice(0,5)}</td>
                        <td style={{padding:"12px 14px",fontSize:13,color:C.black,whiteSpace:"nowrap"}}>{o.staff_name||"—"}</td>
                        <td style={{padding:"12px 14px",fontSize:13,color:C.black,maxWidth:200,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{items.map(i=>i.name).join(", ")}</td>
                        <td style={{padding:"12px 14px"}}><Chip color={o.method==="card"?"blue":o.method==="eft"?"primary":"amber"} size="sm">{o.method||"—"}</Chip></td>
                        <td style={{padding:"12px 14px",fontSize:13,color:C.muted}}>{o.table_num||"—"}</td>
                        <td style={{padding:"12px 14px",fontSize:15,fontWeight:800,color:C.primary,whiteSpace:"nowrap"}}>{fmt(o.total)}</td>
                        <td style={{padding:"12px 14px"}}><Chip color={o.status==="refunded"?"red":"primary"} size="sm">{o.status||"completed"}</Chip></td>
                        <td style={{padding:"12px 14px"}}><Btn variant="secondary" size="sm" onClick={()=>{setView(o);setRefundPin("");setRefundError("")}}>View</Btn></td>
                      </tr>
                    )
                  })}
                </tbody>
              </table>
            </div>
        }
      </div>
      {view&&(
        <Modal title={`Order — ${view.date} ${String(view.time||"").slice(0,5)}`} onClose={()=>setView(null)} width={500}>
          <div style={{display:"flex",flexDirection:"column",gap:14}}>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,fontSize:13}}>
              <div><span style={{color:C.muted}}>Staff: </span><span style={{fontWeight:600,color:C.black}}>{view.staff_name||"—"}</span></div>
              <div><span style={{color:C.muted}}>Method: </span><Chip color="blue" size="sm">{view.method}</Chip></div>
              <div><span style={{color:C.muted}}>Type: </span><span style={{color:C.black}}>{view.order_type}</span></div>
              <div><span style={{color:C.muted}}>Table: </span><span style={{color:C.black}}>{view.table_num||"—"}</span></div>
            </div>
            <div style={{background:C.faint,borderRadius:10,padding:14}}>
              {(typeof view.items==="string"?JSON.parse(view.items||"[]"):view.items||[]).map((item,i)=>(
                <div key={i} style={{display:"flex",justifyContent:"space-between",marginBottom:8,fontSize:14}}>
                  <div>
                    <span style={{fontWeight:600,color:C.black}}>{item.qty}× {item.name}</span>
                    {(item.selections||[]).map(s=>(
                      <div key={s.groupId} style={{fontSize:12,color:C.muted}}>{s.options?.map(o=>o.label).join(", ")}</div>
                    ))}
                    {item.notes&&<div style={{fontSize:12,color:C.amber}}>📝 {item.notes}</div>}
                  </div>
                  <span style={{fontWeight:700,color:C.black}}>{fmt(item.price*item.qty)}</span>
                </div>
              ))}
              <div style={{borderTop:`1px solid ${C.border}`,paddingTop:10,marginTop:6}}>
                {parseFloat(view.discount_amt||0)>0&&<div style={{display:"flex",justifyContent:"space-between",fontSize:13,color:C.green,marginBottom:4}}><span>Discount</span><span>−{fmt(view.discount_amt)}</span></div>}
                {parseFloat(view.tip||0)>0&&<div style={{display:"flex",justifyContent:"space-between",fontSize:13,color:C.amber,marginBottom:4}}><span>Tip</span><span>+{fmt(view.tip)}</span></div>}
                <div style={{display:"flex",justifyContent:"space-between",fontSize:17,fontWeight:800,color:C.primary}}><span>Total</span><span>{fmt(view.total)}</span></div>
              </div>
            </div>
            {view.status!=="refunded"?(
              <div style={{background:"#fff5f5",border:`1px solid ${C.red}30`,borderRadius:10,padding:14}}>
                <div style={{fontSize:13,fontWeight:600,color:C.red,marginBottom:8}}>Refund Order</div>
                <Input label="Manager PIN" type="password" value={refundPin} onChange={e=>{setRefundPin(e.target.value);setRefundError("")}} placeholder="••••"/>
                {refundError&&<div style={{color:C.red,fontSize:13,marginTop:6}}>{refundError}</div>}
                <Btn variant="danger" onClick={doRefund} disabled={refunding||refundPin.length<4} style={{width:"100%",marginTop:10}} size="lg">{refunding?"Processing…":"Issue Refund"}</Btn>
              </div>
            ):(
              <div style={{background:"#fff5f5",borderRadius:10,padding:14,textAlign:"center",color:C.red,fontWeight:700}}>This order has been refunded</div>
            )}
          </div>
        </Modal>
      )}
    </div>
  )
}
// ══════════════════════════════════════════════════════════════════════════════
// MENU MANAGER
// ══════════════════════════════════════════════════════════════════════════════
function MenuModule() {
  const business = useBusiness()
  const {data:cats,   refresh:refreshCats}  = useData("bb_categories")
  const {data:items,  refresh:refreshItems} = useData("bb_menu_items")
  const {data:groups, refresh:refreshGroups}= useData("bb_modifier_groups")
  const {data:options,refresh:refreshOpts}  = useData("bb_modifier_options")
  const {data:links,  refresh:refreshLinks} = useData("bb_item_modifiers")

  const [tab,setTab]           = useState("items")
  const [catModal,setCatModal] = useState(false)
  const [itemModal,setItemModal]= useState(false)
  const [groupModal,setGroupModal]= useState(false)
  const [editCat,setEditCat]   = useState(null)
  const [editItem,setEditItem] = useState(null)
  const [editGroup,setEditGroup]= useState(null)
  const [filterCat,setFilterCat]= useState("all")
  const [saving,setSaving]     = useState(false)

  const [catName,setCatName]   = useState("")
  const [catEmoji,setCatEmoji] = useState("☕")

  const [iName,setIName]       = useState("")
  const [iPrice,setIPrice]     = useState("")
  const [iCost,setICost]       = useState("")
  const [iCat,setICat]         = useState("")
  const [iEmoji,setIEmoji]     = useState("☕")
  const [iDesc,setIDesc]       = useState("")
  const [iTrack,setITrack]     = useState(false)
  const [iStock,setIStock]     = useState("")
  const [iReorder,setIReorder] = useState("")
  const [iImageUrl,setIImageUrl] = useState("")
  const [iAvailFrom,setIAvailFrom] = useState("")
  const [iAvailTo,setIAvailTo]   = useState("")
  const [iLinkedGroups,setILinkedGroups]= useState([])

  const [gName,setGName]       = useState("")
  const [gType,setGType]       = useState("single")
  const [gRequired,setGRequired]= useState(false)
  const [gOptions,setGOptions] = useState([{name:"",price_delta:0}])

  const openNewCat  = () => { setEditCat(null);  setCatName(""); setCatEmoji("☕"); setCatModal(true) }
  const openEditCat = (c)=> { setEditCat(c); setCatName(c.name); setCatEmoji(c.emoji||"☕"); setCatModal(true) }
  const openNewItem = () => { setEditItem(null); setIName(""); setIPrice(""); setICost(""); setICat(""); setIEmoji("☕"); setIDesc(""); setITrack(false); setIStock(""); setIReorder(""); setIImageUrl(""); setIAvailFrom(""); setIAvailTo(""); setILinkedGroups([]); setItemModal(true) }
  const openEditItem= (item)=>{
    setEditItem(item); setIName(item.name); setIPrice(String(item.price)); setICost(String(item.cost||"")); setICat(item.category_id||""); setIEmoji(item.emoji||"☕"); setIDesc(item.description||""); setITrack(item.track_stock||false); setIStock(String(item.stock||"")); setIReorder(String(item.reorder_level||""))
    setILinkedGroups(links.filter(l=>l.item_id===item.id).map(l=>l.group_id))
    setIImageUrl(item.image_url||""); setIAvailFrom(item.available_from||""); setIAvailTo(item.available_to||"")
    setItemModal(true)
  }
  const openNewGroup= () => { setEditGroup(null); setGName(""); setGType("single"); setGRequired(false); setGOptions([{name:"",price_delta:0}]); setGroupModal(true) }

  const saveCat = async () => {
    setSaving(true)
    const p = {name:catName.trim(),emoji:catEmoji,business_id:business.id,active:true,color:"#4a7c59"}
    if(editCat) await supabase.from("bb_categories").update(p).eq("id",editCat.id)
    else await supabase.from("bb_categories").insert({...p,id:uid()})
    await refreshCats(); setSaving(false); setCatModal(false)
  }

  const deleteCat = async (id) => {
    if(!confirm("Delete this category?")) return
    await supabase.from("bb_categories").delete().eq("id",id); await refreshCats()
  }

  const saveItem = async () => {
    setSaving(true)
    const p = {name:iName.trim(),price:parseFloat(iPrice)||0,cost:parseFloat(iCost)||0,category_id:iCat||null,emoji:iEmoji,description:iDesc,track_stock:iTrack,stock:parseFloat(iStock)||0,reorder_level:parseFloat(iReorder)||0,image_url:iImageUrl||null,available_from:iAvailFrom||null,available_to:iAvailTo||null,business_id:business.id,active:true}
    let itemId = editItem?.id
    if(editItem){ await supabase.from("bb_menu_items").update(p).eq("id",itemId) }
    else { itemId=uid(); await supabase.from("bb_menu_items").insert({...p,id:itemId}) }
    await supabase.from("bb_item_modifiers").delete().eq("item_id",itemId)
    if(iLinkedGroups.length>0) await supabase.from("bb_item_modifiers").insert(iLinkedGroups.map(gid=>({id:uid(),business_id:business.id,item_id:itemId,group_id:gid})))
    await refreshItems(); await refreshLinks(); setSaving(false); setItemModal(false)
  }

  const deleteItem = async (id) => {
    if(!confirm("Delete this menu item?")) return
    await supabase.from("bb_menu_items").delete().eq("id",id); await refreshItems()
  }

  const toggleActive = async (item) => {
    await supabase.from("bb_menu_items").update({active:!item.active}).eq("id",item.id); await refreshItems()
  }

  const saveGroup = async () => {
    setSaving(true)
    const groupId = editGroup?.id||uid()
    const p = {id:groupId,name:gName.trim(),selection_type:gType,required:gRequired,business_id:business.id}
    if(editGroup) await supabase.from("bb_modifier_groups").update(p).eq("id",groupId)
    else await supabase.from("bb_modifier_groups").insert(p)
    await supabase.from("bb_modifier_options").delete().eq("group_id",groupId)
    const validOpts=gOptions.filter(o=>o.name.trim())
    if(validOpts.length>0) await supabase.from("bb_modifier_options").insert(validOpts.map((o,i)=>({id:uid(),business_id:business.id,group_id:groupId,name:o.name.trim(),price_delta:parseFloat(o.price_delta)||0,sort_order:i,active:true})))
    await refreshGroups(); await refreshOpts(); setSaving(false); setGroupModal(false)
  }

  const deleteGroup = async (id) => {
    if(!confirm("Delete this modifier group?")) return
    await supabase.from("bb_modifier_options").delete().eq("group_id",id)
    await supabase.from("bb_modifier_groups").delete().eq("id",id)
    await refreshGroups(); await refreshOpts()
  }

  const filteredItems = filterCat==="all"?items:items.filter(i=>i.category_id===filterCat)

  return (
    <div style={{padding:24,display:"flex",flexDirection:"column",gap:20}}>
      <div style={{display:"flex",gap:6,borderBottom:`1px solid ${C.border}`}}>
        {[["items","☕ Menu Items"],["categories","📂 Categories"],["modifiers","🔧 Modifier Groups"]].map(([id,label])=>(
          <button key={id} onClick={()=>setTab(id)} style={{padding:"10px 18px",border:"none",background:"transparent",cursor:"pointer",fontSize:14,fontWeight:tab===id?700:400,color:tab===id?C.primary:C.muted,borderBottom:`2px solid ${tab===id?C.primary:"transparent"}`,fontFamily:"Inter,sans-serif",marginBottom:-1}}>
            {label}
          </button>
        ))}
      </div>

      {tab==="items"&&(
        <>
          <div style={{display:"flex",gap:12,alignItems:"center"}}>
            <div style={{display:"flex",gap:6,overflowX:"auto",flex:1}}>
              {[{id:"all",name:"All",emoji:""},...cats].map(c=>(
                <button key={c.id} onClick={()=>setFilterCat(c.id)} style={{padding:"7px 14px",borderRadius:20,border:"none",cursor:"pointer",whiteSpace:"nowrap",fontFamily:"Inter,sans-serif",fontWeight:600,fontSize:12,background:filterCat===c.id?C.primary:C.faint,color:filterCat===c.id?"#fff":C.muted,flexShrink:0}}>
                  {c.emoji?`${c.emoji} `:""}{c.name}
                </button>
              ))}
            </div>
            <Btn onClick={openNewItem} size="sm">+ Add Item</Btn>
          </div>
          {filteredItems.length===0
            ? <Empty icon="☕" title="No menu items yet" message="Add your first item to get started" action={<Btn onClick={openNewItem}>+ Add Item</Btn>}/>
            : <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(220px,1fr))",gap:12}}>
                {filteredItems.map(item=>{
                  const cat=cats.find(c=>c.id===item.category_id)
                  const itemLinkCount=links.filter(l=>l.item_id===item.id).length
                  return(
                    <div key={item.id} style={{background:C.surface,border:`1px solid ${C.border}`,borderRadius:12,overflow:"hidden",opacity:item.active?1:0.55}}>
                      <div style={{height:80,background:C.faint,display:"flex",alignItems:"center",justifyContent:"center",fontSize:36,position:"relative"}}>
                        {item.image_url?<img src={item.image_url} alt={item.name} style={{width:"100%",height:"100%",objectFit:"cover"}}/>:item.emoji||"☕"}
                        <div style={{position:"absolute",top:6,right:6}}>
                          <button onClick={()=>toggleActive(item)} style={{background:"rgba(0,0,0,.5)",border:"none",borderRadius:6,color:"#fff",cursor:"pointer",fontSize:11,padding:"3px 7px",fontFamily:"Inter,sans-serif"}}>{item.active?"Hide":"Show"}</button>
                        </div>
                      </div>
                      <div style={{padding:"12px 14px"}}>
                        <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:4}}>
                          <div style={{fontSize:14,fontWeight:700,color:C.black,flex:1}}>{item.name}</div>
                          <div style={{fontSize:15,fontWeight:800,color:C.primary,marginLeft:8}}>{fmt(item.price)}</div>
                        </div>
                        {cat&&<Chip color="primary" size="sm">{cat.emoji} {cat.name}</Chip>}
                        {itemLinkCount>0&&<div style={{fontSize:11,color:C.muted,marginTop:4}}>{itemLinkCount} modifier group{itemLinkCount!==1?"s":""}</div>}
                        {item.track_stock&&<div style={{fontSize:11,color:parseFloat(item.stock)<=parseFloat(item.reorder_level)?C.red:C.muted,marginTop:2}}>Stock: {item.stock}</div>}
                        <div style={{display:"flex",gap:6,marginTop:10}}>
                          <Btn variant="secondary" size="sm" onClick={()=>openEditItem(item)} style={{flex:1}}>Edit</Btn>
                          <Btn variant="danger" size="sm" onClick={()=>deleteItem(item.id)}>🗑</Btn>
                        </div>
                      </div>
                    </div>
                  )
                })}
              </div>
          }
        </>
      )}

      {tab==="categories"&&(
        <>
          <div style={{display:"flex",justifyContent:"flex-end"}}><Btn onClick={openNewCat} size="sm">+ Add Category</Btn></div>
          {cats.length===0
            ? <Empty icon="📂" title="No categories yet" message="Add categories to organise your menu" action={<Btn onClick={openNewCat}>+ Add Category</Btn>}/>
            : <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(180px,1fr))",gap:12}}>
                {cats.map(cat=>{
                  const count=items.filter(i=>i.category_id===cat.id).length
                  return(
                    <div key={cat.id} style={{background:C.surface,border:`1px solid ${C.border}`,borderRadius:12,padding:18}}>
                      <div style={{fontSize:36,marginBottom:8}}>{cat.emoji}</div>
                      <div style={{fontSize:16,fontWeight:700,color:C.black,marginBottom:4}}>{cat.name}</div>
                      <div style={{fontSize:12,color:C.muted,marginBottom:12}}>{count} item{count!==1?"s":""}</div>
                      <div style={{display:"flex",gap:6}}>
                        <Btn variant="secondary" size="sm" onClick={()=>openEditCat(cat)} style={{flex:1}}>Edit</Btn>
                        <Btn variant="danger" size="sm" onClick={()=>deleteCat(cat.id)}>🗑</Btn>
                      </div>
                    </div>
                  )
                })}
              </div>
          }
        </>
      )}

      {tab==="modifiers"&&(
        <>
          <div style={{display:"flex",justifyContent:"flex-end"}}><Btn onClick={openNewGroup} size="sm">+ Add Group</Btn></div>
          {groups.length===0
            ? <Empty icon="🔧" title="No modifier groups yet" message='Create groups like "Milk Options", "Extras", "Size"' action={<Btn onClick={openNewGroup}>+ Add Group</Btn>}/>
            : <div style={{display:"flex",flexDirection:"column",gap:10}}>
                {groups.map(group=>{
                  const opts=options.filter(o=>o.group_id===group.id)
                  const linkedCount=links.filter(l=>l.group_id===group.id).length
                  return(
                    <div key={group.id} style={{background:C.surface,border:`1px solid ${C.border}`,borderRadius:12,padding:18}}>
                      <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:10}}>
                        <div>
                          <div style={{fontSize:15,fontWeight:700,color:C.black}}>{group.name}</div>
                          <div style={{fontSize:12,color:C.muted,marginTop:2}}>{group.selection_type==="single"?"Choose one":"Choose many"} · {group.required?"Required":"Optional"} · Used by {linkedCount} item{linkedCount!==1?"s":""}</div>
                        </div>
                        <div style={{display:"flex",gap:6}}>
                          <Btn variant="secondary" size="sm" onClick={()=>{setEditGroup(group);setGName(group.name);setGType(group.selection_type||"single");setGRequired(group.required||false);setGOptions(opts.length>0?opts.map(o=>({name:o.name,price_delta:o.price_delta||0})):[{name:"",price_delta:0}]);setGroupModal(true)}}>Edit</Btn>
                          <Btn variant="danger" size="sm" onClick={()=>deleteGroup(group.id)}>🗑</Btn>
                        </div>
                      </div>
                      <div style={{display:"flex",flexWrap:"wrap",gap:6}}>
                        {opts.map(o=>(
                          <div key={o.id} style={{background:C.faint,borderRadius:8,padding:"5px 10px",fontSize:12,color:C.black}}>{o.name}{parseFloat(o.price_delta||0)>0?` +${fmt(o.price_delta)}`:""}</div>
                        ))}
                      </div>
                    </div>
                  )
                })}
              </div>
          }
        </>
      )}

      {catModal&&(
        <Modal title={editCat?"Edit Category":"New Category"} onClose={()=>setCatModal(false)} width={400}>
          <div style={{display:"flex",flexDirection:"column",gap:14}}>
            <Input label="Category Name" value={catName} onChange={e=>setCatName(e.target.value)} placeholder="e.g. Hot Drinks, Food, Cold Drinks" required/>
            <Input label="Emoji" value={catEmoji} onChange={e=>setCatEmoji(e.target.value)} placeholder="☕"/>
            <div style={{display:"flex",gap:10}}>
              <Btn onClick={saveCat} disabled={saving||!catName.trim()} style={{flex:1}} size="lg">{saving?"Saving…":editCat?"Update":"Create"}</Btn>
              <Btn variant="secondary" onClick={()=>setCatModal(false)} style={{flex:1}} size="lg">Cancel</Btn>
            </div>
          </div>
        </Modal>
      )}

      {itemModal&&(
        <Modal title={editItem?"Edit Item":"New Menu Item"} onClose={()=>setItemModal(false)} width={520}>
          <div style={{display:"flex",flexDirection:"column",gap:14}}>
            <Input label="Item Name" value={iName} onChange={e=>setIName(e.target.value)} placeholder="e.g. Flat White" required/>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
              <Input label="Selling Price (R)" type="number" value={iPrice} onChange={e=>setIPrice(e.target.value)} placeholder="0.00" required/>
              <Input label="Cost Price (R)" type="number" value={iCost} onChange={e=>setICost(e.target.value)} placeholder="0.00"/>
              <Input label="Emoji" value={iEmoji} onChange={e=>setIEmoji(e.target.value)} placeholder="☕"/>
            <div style={{display:"flex",flexDirection:"column",gap:6,gridColumn:"1/-1"}}>
              <label style={{fontSize:13,color:C.muted,fontWeight:500}}>Item Image URL (optional)</label>
              <input value={iImageUrl||""} onChange={e=>setIImageUrl(e.target.value)} placeholder="https://... or leave blank to use emoji"
                style={{background:C.surface,border:`1px solid ${C.border}`,borderRadius:10,color:C.black,padding:"13px 16px",fontSize:14,fontFamily:"Inter,sans-serif",outline:"none"}}/>
              {iImageUrl&&<img src={iImageUrl} alt="preview" style={{width:80,height:80,objectFit:"cover",borderRadius:8,border:`1px solid ${C.border}`}} onError={e=>e.target.style.display="none"}/>}
            </div>
              <div style={{display:"flex",flexDirection:"column",gap:6}}>
                <label style={{fontSize:13,color:C.muted,fontWeight:500}}>Category</label>
                <select value={iCat} onChange={e=>setICat(e.target.value)} style={{background:C.surface,border:`1px solid ${C.border}`,borderRadius:10,color:C.black,padding:"13px 16px",fontSize:15,fontFamily:"Inter,sans-serif",outline:"none"}}>
                  <option value="">No category</option>
                  {cats.map(c=><option key={c.id} value={c.id}>{c.emoji} {c.name}</option>)}
                </select>
              </div>
            </div>
            <Input label="Description (optional)" value={iDesc} onChange={e=>setIDesc(e.target.value)} placeholder="Brief description"/>
            <Toggle value={iTrack} onChange={setITrack} label="Track stock for this item"/>
            <div style={{display:"flex",flexDirection:"column",gap:6}}>
              <label style={{fontSize:13,color:C.muted,fontWeight:500}}>Time-of-day availability (leave blank for always available)</label>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8}}>
                <div style={{display:"flex",flexDirection:"column",gap:4}}>
                  <label style={{fontSize:11,color:C.muted}}>Available from</label>
                  <input type="time" value={iAvailFrom} onChange={e=>setIAvailFrom(e.target.value)}
                    style={{background:C.surface,border:`1px solid ${C.border}`,borderRadius:8,color:C.black,padding:"10px 12px",fontSize:14,fontFamily:"Inter,sans-serif",outline:"none"}}/>
                </div>
                <div style={{display:"flex",flexDirection:"column",gap:4}}>
                  <label style={{fontSize:11,color:C.muted}}>Until</label>
                  <input type="time" value={iAvailTo} onChange={e=>setIAvailTo(e.target.value)}
                    style={{background:C.surface,border:`1px solid ${C.border}`,borderRadius:8,color:C.black,padding:"10px 12px",fontSize:14,fontFamily:"Inter,sans-serif",outline:"none"}}/>
                </div>
              </div>
              {iAvailFrom&&iAvailTo&&<div style={{fontSize:12,color:C.primary}}>✓ Only available {iAvailFrom} – {iAvailTo}</div>}
            </div>
            {iTrack&&(
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
                <Input label="Current Stock" type="number" value={iStock} onChange={e=>setIStock(e.target.value)} placeholder="0"/>
                <Input label="Reorder Level" type="number" value={iReorder} onChange={e=>setIReorder(e.target.value)} placeholder="0"/>
              </div>
            )}
            {groups.length>0&&(
              <div>
                <label style={{fontSize:13,color:C.muted,fontWeight:500,display:"block",marginBottom:8}}>Modifier Groups</label>
                <div style={{display:"flex",flexDirection:"column",gap:6}}>
                  {groups.map(g=>{
                    const linked=iLinkedGroups.includes(g.id)
                    return(
                      <div key={g.id} onClick={()=>setILinkedGroups(prev=>linked?prev.filter(x=>x!==g.id):[...prev,g.id])}
                        style={{display:"flex",alignItems:"center",gap:10,padding:"10px 14px",borderRadius:8,border:`1px solid ${linked?C.primary:C.border}`,background:linked?C.primaryPale:C.faint,cursor:"pointer"}}>
                        <div style={{width:18,height:18,borderRadius:4,border:`2px solid ${linked?C.primary:C.border}`,background:linked?C.primary:"transparent",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>
                          {linked&&<span style={{color:"#fff",fontSize:11}}>✓</span>}
                        </div>
                        <span style={{fontSize:13,fontWeight:linked?600:400,color:linked?C.primary:C.black}}>{g.name}</span>
                        <span style={{fontSize:11,color:C.muted,marginLeft:"auto"}}>{g.selection_type==="single"?"Single":"Multi"}</span>
                      </div>
                    )
                  })}
                </div>
              </div>
            )}
            <div style={{display:"flex",gap:10}}>
              <Btn onClick={saveItem} disabled={saving||!iName.trim()||!iPrice} style={{flex:1}} size="lg">{saving?"Saving…":editItem?"Update Item":"Add to Menu"}</Btn>
              <Btn variant="secondary" onClick={()=>setItemModal(false)} style={{flex:1}} size="lg">Cancel</Btn>
            </div>
          </div>
        </Modal>
      )}

      {groupModal&&(
        <Modal title={editGroup?"Edit Modifier Group":"New Modifier Group"} onClose={()=>setGroupModal(false)} width={500}>
          <div style={{display:"flex",flexDirection:"column",gap:14}}>
            <Input label="Group Name" value={gName} onChange={e=>setGName(e.target.value)} placeholder='e.g. Milk Options, Syrup, Extras' required/>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
              <div style={{display:"flex",flexDirection:"column",gap:6}}>
                <label style={{fontSize:13,color:C.muted,fontWeight:500}}>Selection Type</label>
                <select value={gType} onChange={e=>setGType(e.target.value)} style={{background:C.surface,border:`1px solid ${C.border}`,borderRadius:10,color:C.black,padding:"13px 16px",fontSize:15,fontFamily:"Inter,sans-serif",outline:"none"}}>
                  <option value="single">Single (choose one)</option>
                  <option value="multi">Multi (choose many)</option>
                </select>
              </div>
              <div style={{display:"flex",alignItems:"flex-end",paddingBottom:2}}>
                <Toggle value={gRequired} onChange={setGRequired} label="Required"/>
              </div>
            </div>
            <div>
              <label style={{fontSize:13,color:C.muted,fontWeight:500,display:"block",marginBottom:8}}>Options</label>
              {gOptions.map((opt,i)=>(
                <div key={i} style={{display:"flex",gap:8,marginBottom:8,alignItems:"center"}}>
                  <input value={opt.name} onChange={e=>setGOptions(prev=>prev.map((o,j)=>j===i?{...o,name:e.target.value}:o))} placeholder={`Option ${i+1}`}
                    style={{flex:2,background:C.faint,border:`1px solid ${C.border}`,borderRadius:8,color:C.black,padding:"10px 12px",fontSize:14,fontFamily:"Inter,sans-serif",outline:"none"}}/>
                  <input type="number" value={opt.price_delta||""} onChange={e=>setGOptions(prev=>prev.map((o,j)=>j===i?{...o,price_delta:e.target.value}:o))} placeholder="+0.00"
                    style={{flex:1,background:C.faint,border:`1px solid ${C.border}`,borderRadius:8,color:C.black,padding:"10px 12px",fontSize:14,fontFamily:"Inter,sans-serif",outline:"none"}}/>
                  <button onClick={()=>setGOptions(prev=>prev.filter((_,j)=>j!==i))} style={{background:"none",border:"none",color:C.red,cursor:"pointer",fontSize:18,flexShrink:0}}>×</button>
                </div>
              ))}
              <button onClick={()=>setGOptions(prev=>[...prev,{name:"",price_delta:0}])} style={{background:"none",border:`1px dashed ${C.border}`,borderRadius:8,color:C.primary,cursor:"pointer",padding:"8px 16px",fontSize:13,fontFamily:"Inter,sans-serif",width:"100%",marginTop:4}}>
                + Add Option
              </button>
            </div>
            <div style={{display:"flex",gap:10}}>
              <Btn onClick={saveGroup} disabled={saving||!gName.trim()} style={{flex:1}} size="lg">{saving?"Saving…":editGroup?"Update":"Create Group"}</Btn>
              <Btn variant="secondary" onClick={()=>setGroupModal(false)} style={{flex:1}} size="lg">Cancel</Btn>
            </div>
          </div>
        </Modal>
      )}
    </div>
  )
}
