// FRANCHISE
// ══════════════════════════════════════════════════════════════════════════════
function FranchiseModule() {
  const business = useBusiness()
  const {data:cats,   refresh:refreshCats}  = useData("bb_categories")
  const {data:items,  refresh:refreshItems} = useData("bb_menu_items")
  const {data:groups, refresh:refreshGroups}= useData("bb_modifier_groups")

  const [tab,setTab]         = useState("overview")
  const [branches,setBranches]   = useState([])
  const [loadingBranches,setLoadingBranches] = useState(false)
  const [syncModal,setSyncModal] = useState(false)
  const [syncing,setSyncing]   = useState(false)
  const [syncLog,setSyncLog]   = useState([])
  const [joinModal,setJoinModal] = useState(false)
  const [joinCode,setJoinCode]   = useState("")
  const [joining,setJoining]   = useState(false)
  const [joinError,setJoinError] = useState("")

  const isHQ = business?.is_franchise_hq
  const franchiseCode = business?.franchise_code

  useEffect(()=>{
    if(isHQ) loadBranches()
  },[business?.id])

  const loadBranches = async () => {
    setLoadingBranches(true)
    const {data} = await supabase.from("bb_businesses")
      .select("id,name,plan_id,status,created_at,city")
      .eq("franchise_id",business?.id)
    setBranches(data||[])
    setLoadingBranches(false)
  }

  const generateCode = async () => {
    if(franchiseCode) return
    const code = "BB-"+Math.random().toString(36).slice(2,8).toUpperCase()
    await supabase.from("bb_businesses").update({
      franchise_code: code,
      is_franchise_hq: true,
    }).eq("id",business.id)
    window.location.reload()
  }

  const syncToFranchisees = async () => {
    setSyncing(true)
    setSyncLog([])
    const log = (msg) => setSyncLog(prev=>[...prev,msg])

    try {
      // Get all franchisee businesses
      const {data:franchisees} = await supabase.from("bb_businesses").select("id,name").eq("franchise_id",business.id)
      if(!franchisees||franchisees.length===0){ log("No franchisees found to sync to."); setSyncing(false); return }

      log(`Found ${franchisees.length} franchisee(s)`)

      for(const franchisee of franchisees) {
        log(`Syncing to ${franchisee.name}…`)

        // Sync categories
        for(const cat of cats) {
          const {error} = await supabase.from("bb_categories").upsert({
            ...cat,
            id: cat.id+"_"+franchisee.id.slice(0,8), // unique per franchisee
            business_id: franchisee.id,
            synced_from: cat.id,
          })
          if(!error) log(`  ✓ Category: ${cat.name}`)
        }

        // Sync menu items
        for(const item of items) {
          const {error} = await supabase.from("bb_menu_items").upsert({
            ...item,
            id: item.id+"_"+franchisee.id.slice(0,8),
            business_id: franchisee.id,
            category_id: item.category_id ? item.category_id+"_"+franchisee.id.slice(0,8) : null,
            synced_from: item.id,
          })
          if(!error) log(`  ✓ Item: ${item.name}`)
        }

        // Sync modifier groups
        for(const group of groups) {
          const {error} = await supabase.from("bb_modifier_groups").upsert({
            ...group,
            id: group.id+"_"+franchisee.id.slice(0,8),
            business_id: franchisee.id,
            synced_from: group.id,
          })
          if(!error) log(`  ✓ Modifier: ${group.name}`)
        }

        log(`✓ ${franchisee.name} synced successfully`)
      }
      log("✅ All franchisees synced!")
    } catch(e) {
      log("❌ Sync error: "+e.message)
    }
    setSyncing(false)
  }

  const joinFranchise = async () => {
    setJoinError("")
    if(!joinCode.trim()){ setJoinError("Please enter a franchise code"); return }
    setJoining(true)
    // Find the HQ business by franchise code
    const {data:hq} = await supabase.from("bb_businesses").select("id,name").eq("franchise_code",joinCode.trim().toUpperCase()).single()
    if(!hq){ setJoinError("Franchise code not found. Check the code and try again."); setJoining(false); return }
    // Link this business to the franchise
    await supabase.from("bb_businesses").update({
      franchise_id: hq.id,
      is_franchise_hq: false,
    }).eq("id",business.id)
    setJoining(false)
    setJoinModal(false)
    alert(`Successfully joined ${hq.name} franchise! Refresh the app to see synced menu.`)
  }

  if(!isHQ && !business?.franchise_id) {
    // Not part of any franchise
    return (
      <div style={{padding:24,display:"flex",flexDirection:"column",gap:20}}>
        <div style={{textAlign:"center",padding:"48px 24px",maxWidth:500,margin:"0 auto"}}>
          <div style={{fontSize:56,marginBottom:16}}>🏢</div>
          <div style={{fontSize:24,fontWeight:800,color:C.black,fontFamily:"Playfair Display,serif",marginBottom:8}}>Franchise System</div>
          <div style={{fontSize:14,color:C.muted,marginBottom:32,lineHeight:1.7}}>
            Run a franchise network or join an existing one. As a franchise HQ you can manage multiple branches, sync menus, and view performance across all stores.
          </div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14}}>
            <div style={{background:C.surface,border:`1px solid ${C.border}`,borderRadius:14,padding:24,textAlign:"center"}}>
              <div style={{fontSize:36,marginBottom:10}}>👑</div>
              <div style={{fontSize:16,fontWeight:700,color:C.black,marginBottom:6}}>Start a Franchise</div>
              <div style={{fontSize:13,color:C.muted,marginBottom:16}}>Become a franchise HQ and invite other cafés to join your network</div>
              <Btn onClick={generateCode} style={{width:"100%"}}>Set Up as HQ</Btn>
            </div>
            <div style={{background:C.surface,border:`1px solid ${C.border}`,borderRadius:14,padding:24,textAlign:"center"}}>
              <div style={{fontSize:36,marginBottom:10}}>🤝</div>
              <div style={{fontSize:16,fontWeight:700,color:C.black,marginBottom:6}}>Join a Franchise</div>
              <div style={{fontSize:13,color:C.muted,marginBottom:16}}>Enter a franchise code to sync menus and join an existing network</div>
              <Btn variant="secondary" onClick={()=>setJoinModal(true)} style={{width:"100%"}}>Join Franchise</Btn>
            </div>
          </div>
        </div>

        {joinModal&&(
          <Modal title="Join a Franchise" subtitle="Enter the franchise code from your franchisor" onClose={()=>setJoinModal(false)} width={440}>
            <div style={{display:"flex",flexDirection:"column",gap:14}}>
              <Input label="Franchise Code" value={joinCode} onChange={e=>setJoinCode(e.target.value.toUpperCase())} placeholder="e.g. BB-ABC123"/>
              {joinError&&<div style={{color:C.red,fontSize:13}}>{joinError}</div>}
              <div style={{background:C.faint,borderRadius:8,padding:"10px 14px",fontSize:13,color:C.muted}}>
                Joining a franchise will sync the HQ's menu, categories, and modifier groups to your account. Your staff, shifts, and orders remain private.
              </div>
              <div style={{display:"flex",gap:10}}>
                <Btn onClick={joinFranchise} disabled={joining||!joinCode.trim()} style={{flex:1}} size="lg">{joining?"Joining…":"Join Franchise"}</Btn>
                <Btn variant="secondary" onClick={()=>setJoinModal(false)} style={{flex:1}} size="lg">Cancel</Btn>
              </div>
            </div>
          </Modal>
        )}
      </div>
    )
  }

  if(business?.franchise_id && !isHQ) {
    // Member of a franchise (franchisee)
    return (
      <div style={{padding:24,display:"flex",flexDirection:"column",gap:20}}>
        <div style={{background:`linear-gradient(135deg,${C.primary}15,${C.blue}10)`,border:`1px solid ${C.primary}30`,borderRadius:16,padding:24}}>
          <div style={{display:"flex",alignItems:"center",gap:16,marginBottom:12}}>
            <div style={{width:52,height:52,borderRadius:14,background:C.primary,display:"flex",alignItems:"center",justifyContent:"center",fontSize:24,flexShrink:0}}>🤝</div>
            <div>
              <div style={{fontSize:20,fontWeight:800,color:C.black,fontFamily:"Playfair Display,serif"}}>Franchise Member</div>
              <div style={{fontSize:13,color:C.muted}}>Connected to franchise network</div>
            </div>
          </div>
          <div style={{display:"flex",alignItems:"center",gap:8}}>
            <div style={{width:8,height:8,borderRadius:"50%",background:C.primary}}/>
            <span style={{fontSize:14,color:C.primary,fontWeight:600}}>Connected</span>
            <span style={{fontSize:13,color:C.muted,marginLeft:4}}>Menu syncs automatically from HQ</span>
          </div>
        </div>
        <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(160px,1fr))",gap:14}}>
          <KPI label="Menu Items" value={items.length} icon="☕" sub="synced from HQ"/>
          <KPI label="Categories" value={cats.length} icon="📂" sub="synced from HQ"/>
          <KPI label="Modifier Groups" value={groups.length} icon="🔧" sub="synced from HQ"/>
        </div>
        <div style={{background:C.surface,border:`1px solid ${C.border}`,borderRadius:14,padding:20}}>
          <SHead>What's synced from HQ</SHead>
          <div style={{display:"flex",flexDirection:"column",gap:8}}>
            {["Menu & Categories","Modifier Groups","Pricing","Promotions"].map(item=>(
              <div key={item} style={{display:"flex",alignItems:"center",gap:10,fontSize:14,color:C.black}}>
                <span style={{color:C.primary,fontSize:16}}>✓</span>{item}
              </div>
            ))}
          </div>
          <div style={{marginTop:14,fontSize:13,color:C.muted}}>Your staff, shifts, orders, and expenses remain private to your store.</div>
        </div>
      </div>
    )
  }

  // HQ view
  return (
    <div style={{padding:24,display:"flex",flexDirection:"column",gap:20}}>
      {/* HQ Banner */}
      <div style={{background:`linear-gradient(135deg,${C.primary},${C.blue}80)`,borderRadius:16,padding:24,color:"#fff"}}>
        <div style={{fontSize:13,fontWeight:600,opacity:0.7,marginBottom:4,textTransform:"uppercase",letterSpacing:1}}>Franchise HQ</div>
        <div style={{fontSize:24,fontWeight:800,fontFamily:"Playfair Display,serif",marginBottom:8}}>{business?.name}</div>
        <div style={{display:"flex",alignItems:"center",gap:16,flexWrap:"wrap"}}>
          <div>
            <div style={{fontSize:12,opacity:0.6}}>Franchise Code</div>
            <div style={{fontSize:20,fontWeight:800,fontFamily:"monospace",letterSpacing:2}}>{franchiseCode||"Generating…"}</div>
          </div>
          <div style={{marginLeft:"auto"}}>
            <Btn variant="secondary" size="sm" onClick={()=>navigator.clipboard?.writeText(franchiseCode||"").then(()=>alert("Code copied!"))} style={{background:"rgba(255,255,255,.15)",color:"#fff",borderColor:"rgba(255,255,255,.3)"}}>
              Copy Code
            </Btn>
          </div>
        </div>
        <div style={{fontSize:12,opacity:0.6,marginTop:8}}>Share this code with franchisees so they can join your network</div>
      </div>

      {/* Tabs */}
      <div style={{display:"flex",gap:6,borderBottom:`1px solid ${C.border}`}}>
        {[["overview","Overview"],["branches","Branches"],["sync","Sync Menu"]].map(([id,label])=>(
          <button key={id} onClick={()=>setTab(id)} style={{padding:"10px 18px",border:"none",background:"transparent",cursor:"pointer",fontSize:14,fontWeight:tab===id?700:400,color:tab===id?C.primary:C.muted,borderBottom:`2px solid ${tab===id?C.primary:"transparent"}`,fontFamily:"Inter,sans-serif",marginBottom:-1}}>{label}</button>
        ))}
      </div>

      {tab==="overview"&&(
        <div style={{display:"flex",flexDirection:"column",gap:16}}>
          <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(160px,1fr))",gap:14}}>
            <KPI label="Branches" value={branches.length} icon="🏪" sub="active locations"/>
            <KPI label="Menu Items" value={items.length} icon="☕" sub="in HQ menu"/>
            <KPI label="Categories" value={cats.length} icon="📂"/>
            <KPI label="Modifier Groups" value={groups.length} icon="🔧"/>
          </div>
          <div style={{background:C.surface,border:`1px solid ${C.border}`,borderRadius:14,padding:20}}>
            <SHead>Quick Actions</SHead>
            <div style={{display:"flex",gap:10,flexWrap:"wrap"}}>
              <Btn onClick={()=>{setSyncModal(true);setSyncLog([])}} icon="🔄">Sync Menu to All Branches</Btn>
              <Btn variant="secondary" onClick={()=>setTab("branches")} icon="🏪">View Branches</Btn>
            </div>
          </div>
        </div>
      )}

      {tab==="branches"&&(
        <div style={{display:"flex",flexDirection:"column",gap:12}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
            <div style={{fontSize:14,color:C.muted}}>{branches.length} branch{branches.length!==1?"es":""}</div>
            <Btn size="sm" variant="secondary" onClick={loadBranches}>Refresh</Btn>
          </div>
          {loadingBranches?(
            <div style={{textAlign:"center",padding:32}}><Spinner size={32}/></div>
          ):branches.length===0?(
            <Empty icon="🏪" title="No branches yet" message="Share your franchise code with other café owners to add branches"/>
          ):branches.map(branch=>(
            <div key={branch.id} style={{background:C.surface,border:`1px solid ${C.border}`,borderRadius:12,padding:18,display:"flex",justifyContent:"space-between",alignItems:"center",gap:12,flexWrap:"wrap"}}>
              <div>
                <div style={{fontSize:15,fontWeight:700,color:C.black}}>{branch.name}</div>
                <div style={{fontSize:13,color:C.muted}}>{branch.city||"Location not set"} · Joined {new Date(branch.created_at).toLocaleDateString("en-ZA")}</div>
              </div>
              <Chip color={branch.status==="active"?"primary":"red"} size="sm">{branch.status||"active"}</Chip>
            </div>
          ))}
        </div>
      )}

      {tab==="sync"&&(
        <div style={{display:"flex",flexDirection:"column",gap:16}}>
          <div style={{background:C.surface,border:`1px solid ${C.border}`,borderRadius:14,padding:20}}>
            <SHead>Sync to Franchisees</SHead>
            <div style={{fontSize:14,color:C.muted,marginBottom:16}}>Push your current menu, categories, and modifier groups to all franchise branches. This will overwrite their synced content.</div>
            <div style={{display:"flex",flexDirection:"column",gap:8,marginBottom:20}}>
              {[`${cats.length} categories`,`${items.length} menu items`,`${groups.length} modifier groups`].map(item=>(
                <div key={item} style={{display:"flex",alignItems:"center",gap:8,fontSize:14,color:C.black}}>
                  <span style={{color:C.primary}}>✓</span>{item} will be synced
                </div>
              ))}
            </div>
            <Btn onClick={()=>{setSyncModal(true);setSyncLog([]);syncToFranchisees()}} disabled={syncing||branches.length===0} size="lg">
              {syncing?"Syncing…":"🔄 Sync to All Branches"}
            </Btn>
            {branches.length===0&&<div style={{fontSize:13,color:C.muted,marginTop:8}}>No branches to sync to yet</div>}
          </div>

          {syncLog.length>0&&(
            <div style={{background:"#0e0e0e",borderRadius:12,padding:16}}>
              <div style={{fontSize:12,color:"rgba(255,255,255,.4)",marginBottom:8,fontFamily:"monospace"}}>Sync Log</div>
              {syncLog.map((line,i)=>(
                <div key={i} style={{fontSize:13,fontFamily:"monospace",color:line.startsWith("✅")||line.startsWith("✓")?"#4ade80":line.startsWith("❌")?"#f87171":"rgba(255,255,255,.7)",marginBottom:3}}>{line}</div>
              ))}
            </div>
          )}
        </div>
      )}
    </div>
  )
}

